1	package com.example.ricms.security;
2	
3	import lombok.RequiredArgsConstructor;
4	import org.springframework.context.annotation.Bean;
5	import org.springframework.context.annotation.Configuration;
6	import org.springframework.http.HttpMethod;
7	import org.springframework.security.authentication.AuthenticationManager;
8	import org.springframework.security.authentication.dao.DaoAuthenticationProvider;
9	import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
10	import org.springframework.security.config.annotation.web.builders.HttpSecurity;
11	import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
12	import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
13	import org.springframework.security.config.http.SessionCreationPolicy;
14	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
15	import org.springframework.security.crypto.password.PasswordEncoder;
16	import org.springframework.security.web.SecurityFilterChain;
17	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
18	
19	@Configuration
20	@EnableWebSecurity
21	@RequiredArgsConstructor
22	public class SecurityConfig {
23	
24	    private final JwtFilter jwtFilter;
25	    private final UserDetailsServiceImpl userDetailsService;
26	
27	    @Bean
28	    public PasswordEncoder passwordEncoder() {
29	        return new BCryptPasswordEncoder(10);
30	    }
31	
32	    @Bean
33	    public DaoAuthenticationProvider authenticationProvider() {
34	        DaoAuthenticationProvider provider = new DaoAuthenticationProvider();
35	        provider.setUserDetailsService(userDetailsService);
36	        provider.setPasswordEncoder(passwordEncoder());
37	        return provider;
38	    }
39	
40	    @Bean
41	    public AuthenticationManager authenticationManager(AuthenticationConfiguration config) throws Exception {
42	        return config.getAuthenticationManager();
43	    }
44	
45	    @Bean
46	    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
47	        http
48	            .csrf(AbstractHttpConfigurer::disable)
49	            .sessionManagement(sm -> sm.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
50	            .authorizeHttpRequests(auth -> auth
51	                .requestMatchers(HttpMethod.POST, "/v1/auth/login").permitAll()
52	                .requestMatchers("/actuator/**").permitAll()
53	                .anyRequest().authenticated()
54	            )
55	            .authenticationProvider(authenticationProvider())
56	            .addFilterBefore(jwtFilter, UsernamePasswordAuthenticationFilter.class);
57	
58	        return http.build();
59	    }
60	}
