1	package com.example.ricms.service;
2	
3	import com.example.ricms.domain.entity.*;
4	import com.example.ricms.domain.enums.OrderStatus;
5	import com.example.ricms.dto.request.PlaceOrderRequest;
6	import com.example.ricms.dto.response.OrderItemResponse;
7	import com.example.ricms.dto.response.OrderResponse;
8	import com.example.ricms.dto.response.PageResponse;
9	import com.example.ricms.dto.response.PricingResult;
10	import com.example.ricms.exception.AppException;
11	import com.example.ricms.repository.*;
12	import lombok.RequiredArgsConstructor;
13	import lombok.extern.slf4j.Slf4j;
14	import org.springframework.data.domain.Page;
15	import org.springframework.data.domain.PageRequest;
16	import org.springframework.http.HttpStatus;
17	import org.springframework.stereotype.Service;
18	import org.springframework.transaction.annotation.Transactional;
19	
20	import java.math.BigDecimal;
21	import java.nio.charset.StandardCharsets;
22	import java.security.MessageDigest;
23	import java.time.OffsetDateTime;
24	import java.util.ArrayList;
25	import java.util.List;
26	import java.util.Optional;
27	import java.util.UUID;
28	import java.util.concurrent.atomic.AtomicLong;
29	import java.util.stream.Collectors;
30	
31	@Slf4j
32	@Service
33	@RequiredArgsConstructor
34	public class OrderService {
35	
36	    private final OrderRepository orderRepository;
37	    private final OrderItemRepository orderItemRepository;
38	    private final OrderNoteRepository orderNoteRepository;
39	    private final InventoryRepository inventoryRepository;
40	    private final MemberRepository memberRepository;
41	    private final MemberService memberService;
42	    private final PricingEngine pricingEngine;
43	    private final AuditService auditService;
44	
45	    private static final AtomicLong orderSeq = new AtomicLong(System.currentTimeMillis() % 100000);
46	
47	    @Transactional
48	    public OrderResponse placeOrder(PlaceOrderRequest request, String idempotencyKey) {
49	        // Check idempotency
50	        if (idempotencyKey != null && !idempotencyKey.isBlank()) {
51	            String keyHash = hashIdempotencyKey(request.getBuyerId(), idempotencyKey);
52	            Optional<Order> existing = orderRepository.findByBuyerUserIdAndIdempotencyKeyHash(
53	                    request.getBuyerId(), keyHash);
54	            if (existing.isPresent()) {
55	                Order existingOrder = existing.get();
56	                if (existingOrder.getCreatedAt().isAfter(OffsetDateTime.now().minusMinutes(10))) {
57	                    return toResponse(existingOrder);
58	                }
59	            }
60	        }
61	
62	        // Compute subtotal
63	        BigDecimal subtotal = request.getItems().stream()
64	                .map(item -> item.getUnitPrice().multiply(BigDecimal.valueOf(item.getQuantity())))
65	                .reduce(BigDecimal.ZERO, BigDecimal::add);
66	
67	        BigDecimal shippingCost = computeShipping(request.getShippingCountry());
68	
69	        // Pricing
70	        PricingResult pricing = pricingEngine.computePricing(
71	                request.getBuyerId(), subtotal, shippingCost,
72	                request.getCouponCode(), request.getCampaignId());
73	
74	        // Reserve inventory
75	        for (var item : request.getItems()) {
76	            Inventory inv = inventoryRepository.findBySkuWithLock(item.getSku())
77	                    .orElseThrow(() -> new AppException("INVENTORY_NOT_FOUND",
78	                            "SKU not found: " + item.getSku(), HttpStatus.BAD_REQUEST));
79	            int available = inv.getOnHand() - inv.getReserved();
80	            if (available < item.getQuantity()) {
81	                throw new AppException("INSUFFICIENT_INVENTORY",
82	                        "Insufficient inventory for SKU: " + item.getSku(), HttpStatus.CONFLICT);
83	            }
84	            inv.setReserved(inv.getReserved() + item.getQuantity());
85	            inv.setReservedUntil(OffsetDateTime.now().plusMinutes(30));
86	            inventoryRepository.save(inv);
87	        }
88	
89	        // Create order
90	        String orderNumber = "ORD-" + System.currentTimeMillis() + "-" + orderSeq.incrementAndGet();
91	        String idempotencyKeyHash = idempotencyKey != null ?
92	                hashIdempotencyKey(request.getBuyerId(), idempotencyKey) : null;
93	
94	        Order order = Order.builder()
95	                .orderNumber(orderNumber)
96	                .buyerUserId(request.getBuyerId())
97	                .status(OrderStatus.PLACED)
98	                .subtotal(subtotal)
99	                .discountsTotal(pricing.getDiscountsTotal())
100	                .shippingTotal(pricing.getShippingTotal())
101	                .totalPayable(pricing.getTotalPayable())
102	                .couponId(pricing.getAppliedCouponId())
103	                .campaignId(pricing.getAppliedCampaignId())
104	                .paymentMethod(request.getPaymentMethod())
105	                .shippingCountry(request.getShippingCountry())
106	                .shippingPostalCode(request.getShippingPostalCode())
107	                .idempotencyKeyHash(idempotencyKeyHash)
108	                .items(new ArrayList<>())
109	                .build();
110	
111	        order = orderRepository.save(order);
112	
113	        // Create items
114	        List<OrderItem> items = new ArrayList<>();
115	        for (var itemDto : request.getItems()) {
116	            OrderItem item = OrderItem.builder()
117	                    .orderId(order.getId())
118	                    .sku(itemDto.getSku())
119	                    .quantity(itemDto.getQuantity())
120	                    .unitPrice(itemDto.getUnitPrice())
121	                    .lineTotal(itemDto.getUnitPrice().multiply(BigDecimal.valueOf(itemDto.getQuantity())))
122	                    .build();
123	            items.add(orderItemRepository.save(item));
124	        }
125	        order.setItems(items);
126	
127	        auditService.record(request.getBuyerId(), "ORDER", order.getId().toString(),
128	                "PLACE_ORDER", "USER_ACTION", null, orderNumber);
129	
130	        return toResponse(order);
131	    }
132	
133	    public PageResponse<OrderResponse> getOrders(int page, int pageSize, UUID buyerId,
134	                                                  String statusStr, String orderNumber) {
135	        OrderStatus status = null;
136	        if (statusStr != null && !statusStr.isBlank()) {
137	            try {
138	                status = OrderStatus.valueOf(statusStr);
139	            } catch (Exception e) {
140	                throw new AppException("INVALID_STATUS", "Invalid order status: " + statusStr, HttpStatus.BAD_REQUEST);
141	            }
142	        }
143	        Page<Order> orders = orderRepository.findByBuyerUserIdWithFilters(
144	                buyerId, status, orderNumber, PageRequest.of(page, pageSize));
145	        return PageResponse.of(orders.map(this::toResponse));
146	    }
147	
148	    public OrderResponse getOrder(UUID orderId) {
149	        Order order = orderRepository.findById(orderId)
150	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
151	        return toResponse(order);
152	    }
153	
154	    @Transactional
155	    public OrderResponse confirmPayment(UUID orderId, String paymentRef) {
156	        Order order = orderRepository.findById(orderId)
157	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
158	
159	        if (order.getStatus() != OrderStatus.PLACED) {
160	            throw new AppException("INVALID_STATE_TRANSITION",
161	                    "Order must be in PLACED status to confirm payment", HttpStatus.CONFLICT);
162	        }
163	
164	        order.setStatus(OrderStatus.CONFIRMED_PAYMENT);
165	        order.setPaymentConfirmedAt(OffsetDateTime.now());
166	        orderRepository.save(order);
167	
168	        // Accrue points for member
169	        memberRepository.findByUserId(order.getBuyerUserId()).ifPresent(member ->
170	            memberService.accruePoints(member.getId(), orderId, order.getTotalPayable())
171	        );
172	
173	        auditService.record(order.getBuyerUserId(), "ORDER", orderId.toString(),
174	                "CONFIRM_PAYMENT", "PAYMENT_CONFIRMED", OrderStatus.PLACED, OrderStatus.CONFIRMED_PAYMENT);
175	
176	        return toResponse(order);
177	    }
178	
179	    @Transactional
180	    public OrderResponse fulfillOrder(UUID orderId) {
181	        Order order = orderRepository.findById(orderId)
182	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
183	
184	        if (order.getStatus() != OrderStatus.CONFIRMED_PAYMENT) {
185	            throw new AppException("INVALID_STATE_TRANSITION",
186	                    "Order must be in CONFIRMED_PAYMENT status to fulfill", HttpStatus.CONFLICT);
187	        }
188	        order.setStatus(OrderStatus.FULFILLMENT_RESERVED);
189	        orderRepository.save(order);
190	        return toResponse(order);
191	    }
192	
193	    @Transactional
194	    public OrderResponse confirmDelivery(UUID orderId) {
195	        Order order = orderRepository.findById(orderId)
196	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
197	
198	        if (order.getStatus() != OrderStatus.FULFILLMENT_RESERVED) {
199	            throw new AppException("INVALID_STATE_TRANSITION",
200	                    "Order must be in FULFILLMENT_RESERVED status", HttpStatus.CONFLICT);
201	        }
202	        order.setStatus(OrderStatus.DELIVERY_CONFIRMED);
203	        orderRepository.save(order);
204	
205	        // Deduct from inventory reservation
206	        List<OrderItem> items = orderItemRepository.findByOrderId(orderId);
207	        for (OrderItem item : items) {
208	            inventoryRepository.findBySkuWithLock(item.getSku()).ifPresent(inv -> {
209	                inv.setReserved(Math.max(0, inv.getReserved() - item.getQuantity()));
210	                inv.setOnHand(Math.max(0, inv.getOnHand() - item.getQuantity()));
211	                inventoryRepository.save(inv);
212	            });
213	        }
214	
215	        return toResponse(order);
216	    }
217	
218	    @Transactional
219	    public OrderResponse completeOrder(UUID orderId) {
220	        Order order = orderRepository.findById(orderId)
221	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
222	
223	        if (order.getStatus() != OrderStatus.DELIVERY_CONFIRMED) {
224	            throw new AppException("INVALID_STATE_TRANSITION",
225	                    "Order must be in DELIVERY_CONFIRMED status", HttpStatus.CONFLICT);
226	        }
227	        order.setStatus(OrderStatus.COMPLETED);
228	        orderRepository.save(order);
229	        return toResponse(order);
230	    }
231	
232	    @Transactional
233	    public void addNote(UUID orderId, String note, UUID authorId) {
234	        Order order = orderRepository.findById(orderId)
235	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
236	
237	        OrderNote orderNote = OrderNote.builder()
238	                .orderId(orderId)
239	                .authorUserId(authorId)
240	                .noteText(note)
241	                .build();
242	        orderNoteRepository.save(orderNote);
243	    }
244	
245	    @Transactional
246	    public void closeTimedOutOrders() {
247	        OffsetDateTime cutoff = OffsetDateTime.now().minusMinutes(30);
248	        List<Order> timedOut = orderRepository.findTimedOutOrders(cutoff);
249	
250	        for (Order order : timedOut) {
251	            log.info("Closing timed-out order: {}", order.getOrderNumber());
252	            // Release inventory
253	            List<OrderItem> items = orderItemRepository.findByOrderId(order.getId());
254	            for (OrderItem item : items) {
255	                inventoryRepository.findBySkuWithLock(item.getSku()).ifPresent(inv -> {
256	                    inv.setReserved(Math.max(0, inv.getReserved() - item.getQuantity()));
257	                    inventoryRepository.save(inv);
258	                });
259	            }
260	            order.setStatus(OrderStatus.CLOSED);
261	            order.setClosedAt(OffsetDateTime.now());
262	            orderRepository.save(order);
263	        }
264	    }
265	
266	    private BigDecimal computeShipping(String country) {
267	        // Simple flat rate
268	        if ("US".equalsIgnoreCase(country)) return BigDecimal.valueOf(10.00);
269	        if (country == null) return BigDecimal.valueOf(15.00);
270	        return BigDecimal.valueOf(25.00);
271	    }
272	
273	    private String hashIdempotencyKey(UUID buyerId, String key) {
274	        try {
275	            MessageDigest md = MessageDigest.getInstance("SHA-256");
276	            byte[] hash = md.digest((buyerId.toString() + ":" + key).getBytes(StandardCharsets.UTF_8));
277	            StringBuilder sb = new StringBuilder();
278	            for (byte b : hash) sb.append(String.format("%02x", b));
279	            return sb.toString();
280	        } catch (Exception e) {
281	            return key;
282	        }
283	    }
284	
285	    public OrderResponse toResponse(Order order) {
286	        // Load items from DB (since items is @Transient on Order)
287	        List<OrderItem> dbItems = order.getItems() != null && !order.getItems().isEmpty()
288	                ? order.getItems()
289	                : orderItemRepository.findByOrderId(order.getId());
290	        List<OrderItemResponse> itemResponses = dbItems.stream()
291	                .map(this::toItemResponse).collect(Collectors.toList());
292	
293	        return OrderResponse.builder()
294	                .id(order.getId())
295	                .orderNumber(order.getOrderNumber())
296	                .buyerUserId(order.getBuyerUserId())
297	                .status(order.getStatus())
298	                .subtotal(order.getSubtotal())
299	                .discountsTotal(order.getDiscountsTotal())
300	                .shippingTotal(order.getShippingTotal())
301	                .totalPayable(order.getTotalPayable())
302	                .paymentMethod(order.getPaymentMethod())
303	                .shippingCountry(order.getShippingCountry())
304	                .shippingPostalCode(order.getShippingPostalCode())
305	                .items(itemResponses)
306	                .createdAt(order.getCreatedAt())
307	                .closedAt(order.getClosedAt())
308	                .paymentConfirmedAt(order.getPaymentConfirmedAt())
309	                .build();
310	    }
311	
312	    private OrderItemResponse toItemResponse(OrderItem item) {
313	        return OrderItemResponse.builder()
314	                .id(item.getId())
315	                .sku(item.getSku())
316	                .quantity(item.getQuantity())
317	                .unitPrice(item.getUnitPrice())
318	                .lineTotal(item.getLineTotal())
319	                .build();
320	    }
321	}
