1	package com.example.ricms.exception;
2	
3	import jakarta.validation.ConstraintViolationException;
4	import org.springframework.http.HttpHeaders;
5	import org.springframework.http.HttpStatus;
6	import org.springframework.http.ResponseEntity;
7	import org.springframework.security.access.AccessDeniedException;
8	import org.springframework.security.core.AuthenticationException;
9	import org.springframework.validation.FieldError;
10	import org.springframework.web.bind.MethodArgumentNotValidException;
11	import org.springframework.web.bind.annotation.ExceptionHandler;
12	import org.springframework.web.bind.annotation.RestControllerAdvice;
13	
14	import java.util.HashMap;
15	import java.util.Map;
16	import java.util.stream.Collectors;
17	
18	@RestControllerAdvice
19	public class GlobalExceptionHandler {
20	
21	    @ExceptionHandler(AppException.class)
22	    public ResponseEntity<Map<String, Object>> handleAppException(AppException ex) {
23	        Map<String, Object> body = buildError(ex.getCode(), ex.getMessage(), null);
24	        return ResponseEntity.status(ex.getStatus()).body(body);
25	    }
26	
27	    @ExceptionHandler(RateLimitException.class)
28	    public ResponseEntity<Map<String, Object>> handleRateLimit(RateLimitException ex) {
29	        Map<String, Object> body = buildError(ex.getCode(), ex.getMessage(), null);
30	        HttpHeaders headers = new HttpHeaders();
31	        headers.set("Retry-After", String.valueOf(ex.getRetryAfterSeconds()));
32	        return ResponseEntity.status(HttpStatus.TOO_MANY_REQUESTS).headers(headers).body(body);
33	    }
34	
35	    @ExceptionHandler(MethodArgumentNotValidException.class)
36	    public ResponseEntity<Map<String, Object>> handleValidation(MethodArgumentNotValidException ex) {
37	        Map<String, String> fieldErrors = ex.getBindingResult().getFieldErrors().stream()
38	                .collect(Collectors.toMap(
39	                        FieldError::getField,
40	                        fe -> fe.getDefaultMessage() == null ? "Invalid value" : fe.getDefaultMessage(),
41	                        (a, b) -> a
42	                ));
43	        Map<String, Object> body = buildError("VALIDATION_ERROR", "Request validation failed", fieldErrors);
44	        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
45	    }
46	
47	    @ExceptionHandler(ConstraintViolationException.class)
48	    public ResponseEntity<Map<String, Object>> handleConstraintViolation(ConstraintViolationException ex) {
49	        String message = ex.getConstraintViolations().stream()
50	                .map(cv -> cv.getPropertyPath() + ": " + cv.getMessage())
51	                .collect(Collectors.joining("; "));
52	        Map<String, Object> body = buildError("CONSTRAINT_VIOLATION", message, null);
53	        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
54	    }
55	
56	    @ExceptionHandler(AccessDeniedException.class)
57	    public ResponseEntity<Map<String, Object>> handleAccessDenied(AccessDeniedException ex) {
58	        Map<String, Object> body = buildError("ACCESS_DENIED", "You do not have permission to perform this action", null);
59	        return ResponseEntity.status(HttpStatus.FORBIDDEN).body(body);
60	    }
61	
62	    @ExceptionHandler(AuthenticationException.class)
63	    public ResponseEntity<Map<String, Object>> handleAuth(AuthenticationException ex) {
64	        Map<String, Object> body = buildError("UNAUTHORIZED", ex.getMessage(), null);
65	        return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(body);
66	    }
67	
68	    @ExceptionHandler(Exception.class)
69	    public ResponseEntity<Map<String, Object>> handleGeneral(Exception ex) {
70	        Map<String, Object> body = buildError("INTERNAL_ERROR", "An unexpected error occurred", null);
71	        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(body);
72	    }
73	
74	    private Map<String, Object> buildError(String code, String message, Object details) {
75	        Map<String, Object> errorInner = new HashMap<>();
76	        errorInner.put("code", code);
77	        errorInner.put("message", message);
78	        if (details != null) {
79	            errorInner.put("details", details);
80	        }
81	        Map<String, Object> body = new HashMap<>();
82	        body.put("error", errorInner);
83	        return body;
84	    }
