1	package com.example.ricms.security;
2	
3	import com.example.ricms.config.AppProperties;
4	import io.jsonwebtoken.*;
5	import io.jsonwebtoken.security.Keys;
6	import lombok.RequiredArgsConstructor;
7	import lombok.extern.slf4j.Slf4j;
8	import org.springframework.stereotype.Component;
9	
10	import javax.crypto.SecretKey;
11	import java.nio.charset.StandardCharsets;
12	import java.util.Date;
13	import java.util.UUID;
14	
15	@Slf4j
16	@Component
17	@RequiredArgsConstructor
18	public class JwtUtil {
19	
20	    private final AppProperties appProperties;
21	
22	    private SecretKey getSigningKey() {
23	        String secret = appProperties.getJwt().getSecret();
24	        // Ensure key is at least 256 bits
25	        byte[] keyBytes = secret.getBytes(StandardCharsets.UTF_8);
26	        if (keyBytes.length < 32) {
27	            // pad to 32 bytes
28	            byte[] padded = new byte[32];
29	            System.arraycopy(keyBytes, 0, padded, 0, keyBytes.length);
30	            return Keys.hmacShaKeyFor(padded);
31	        }
32	        return Keys.hmacShaKeyFor(keyBytes);
33	    }
34	
35	    public String generateToken(UUID userId, String username) {
36	        long now = System.currentTimeMillis();
37	        return Jwts.builder()
38	                .subject(userId.toString())
39	                .claim("username", username)
40	                .issuedAt(new Date(now))
41	                .expiration(new Date(now + appProperties.getJwt().getExpirationMs()))
42	                .signWith(getSigningKey(), Jwts.SIG.HS256)
43	                .compact();
44	    }
45	
46	    public boolean validateToken(String token) {
47	        try {
48	            Jwts.parser()
49	                    .verifyWith(getSigningKey())
50	                    .build()
51	                    .parseSignedClaims(token);
52	            return true;
53	        } catch (ExpiredJwtException e) {
54	            log.debug("JWT expired: {}", e.getMessage());
55	        } catch (JwtException e) {
56	            log.debug("JWT invalid: {}", e.getMessage());
57	        }
58	        return false;
59	    }
60	
61	    private Claims extractClaims(String token) {
62	        return Jwts.parser()
63	                .verifyWith(getSigningKey())
64	                .build()
65	                .parseSignedClaims(token)
66	                .getPayload();
67	    }
68	
69	    public UUID getUserId(String token) {
70	        return UUID.fromString(extractClaims(token).getSubject());
71	    }
72	
73	    public String getUsername(String token) {
74	        return (String) extractClaims(token).get("username");
75	    }
76	}
