6	import com.example.ricms.dto.response.DuplicateCheckResponse;
7	import com.example.ricms.dto.response.OutcomeResponse;
8	import com.example.ricms.dto.response.PageResponse;
9	import com.example.ricms.exception.AppException;
10	import com.example.ricms.repository.*;
11	import lombok.RequiredArgsConstructor;
12	import lombok.extern.slf4j.Slf4j;
13	import org.springframework.data.domain.PageRequest;
14	import org.springframework.http.HttpStatus;
15	import org.springframework.stereotype.Service;
16	import org.springframework.transaction.annotation.Transactional;
17	
18	import java.math.BigDecimal;
19	import java.util.*;
20	import java.util.stream.Collectors;
21	
22	@Slf4j
23	@Service
24	@RequiredArgsConstructor
25	public class OutcomeService {
26	
27	    private final OutcomeRepository outcomeRepository;
28	    private final ContributionRepository contributionRepository;
29	    private final OutcomeEvidenceRepository outcomeEvidenceRepository;
30	    private final ModerationQueueRepository moderationQueueRepository;
31	    private final AuditService auditService;
32	
33	    @Transactional
34	    public OutcomeResponse registerOutcome(OutcomeCreateRequest request, UUID actorId) {
35	        // Validate contributions sum to 100%
36	        if (request.getContributions() == null || request.getContributions().isEmpty()) {
37	            throw new AppException("INVALID_CONTRIBUTIONS", "At least one contribution is required", HttpStatus.BAD_REQUEST);
38	        }
39	        BigDecimal totalShare = request.getContributions().stream()
40	                .map(c -> c.getSharePercent() != null ? c.getSharePercent() : BigDecimal.ZERO)
41	                .reduce(BigDecimal.ZERO, BigDecimal::add);
42	        if (totalShare.compareTo(new BigDecimal("100.00")) != 0) {
43	            throw new AppException("INVALID_CONTRIBUTIONS",
44	                    "Contributions must sum to exactly 100%, got: " + totalShare, HttpStatus.BAD_REQUEST);
45	        }
46	
47	        // Normalize title
48	        String titleNormalized = normalizeTitle(request.getTitle());
49	
50	        // Check certificate uniqueness
51	        if (request.getCertificateNumber() != null && !request.getCertificateNumber().isBlank()) {
52	            outcomeRepository.findByCertificateNumber(request.getCertificateNumber())
53	                    .ifPresent(existing -> {
54	                        throw new AppException("DUPLICATE_CERTIFICATE",
55	                                "Certificate number already exists", HttpStatus.CONFLICT);
56	                    });
57	        }
58	
59	        // Check for duplicates
60	        DuplicateCheckResponse dupCheck = checkDuplicateInternal(titleNormalized, request.getAbstractText());
61	        String status = dupCheck.isDuplicateFound() ? "UNDER_REVIEW" : "ACTIVE";
62	
63	        Outcome outcome = Outcome.builder()
64	                .type(request.getType())
65	                .projectId(request.getProjectId())
66	                .titleOriginal(request.getTitle())
67	                .titleNormalized(titleNormalized)
68	                .abstractText(request.getAbstractText())
69	                .certificateNumber(request.getCertificateNumber())
70	                .status(status)
71	                .build();
72	        outcome = outcomeRepository.save(outcome);
73	
74	        // Save contributions
75	        for (var contribDto : request.getContributions()) {
76	            Contribution c = Contribution.builder()
77	                    .outcomeId(outcome.getId())
78	                    .contributorUserId(contribDto.getContributorId())
79	                    .sharePercent(contribDto.getSharePercent())
80	                    .build();
81	            contributionRepository.save(c);
82	        }
83	
84	        // Save evidences
85	        if (request.getEvidences() != null) {
86	            for (var evDto : request.getEvidences()) {
87	                OutcomeEvidence ev = OutcomeEvidence.builder()
88	                        .outcomeId(outcome.getId())
89	                        .evidenceType(evDto.getEvidenceType())
90	                        .blobRef(evDto.getBlobRef())
91	                        .build();
92	                outcomeEvidenceRepository.save(ev);
93	            }
94	        }
95	
96	        // If duplicate suspected, add to moderation queue
97	        if (dupCheck.isDuplicateFound()) {
98	            ModerationQueue mq = ModerationQueue.builder()
99	                    .queueType("DUPLICATE_REVIEW")
100	                    .targetType("OUTCOME")
101	                    .targetId(outcome.getId())
102	                    .payload("{\"reason\":\"" + dupCheck.getReason() + "\"}")
103	                    .status("PENDING")
104	                    .build();
105	            moderationQueueRepository.save(mq);
106	        }
107	
108	        auditService.record(actorId, "OUTCOME", outcome.getId().toString(),
109	                "REGISTER", "USER_ACTION", null, outcome.getTitleOriginal());
110	
111	        return toResponse(outcome);
112	    }
113	
114	    public DuplicateCheckResponse checkDuplicate(OutcomeCreateRequest request) {
115	        String normalized = normalizeTitle(request.getTitle());
116	        return checkDuplicateInternal(normalized, request.getAbstractText());
117	    }
118	
119	    private DuplicateCheckResponse checkDuplicateInternal(String titleNormalized, String abstractText) {
120	        List<Outcome> exactMatches = outcomeRepository.findByTitleNormalized(titleNormalized);
121	        if (!exactMatches.isEmpty()) {
122	            return DuplicateCheckResponse.builder()
123	                    .duplicateFound(true)
124	                    .matchingOutcomeIds(exactMatches.stream().map(Outcome::getId).collect(Collectors.toList()))
125	                    .reason("Exact title match found")
126	                    .build();
127	        }
128	
129	        // Check abstract token overlap
130	        if (abstractText != null && !abstractText.isBlank()) {
131	            List<Outcome> allOutcomes = outcomeRepository.findAll();
132	            List<UUID> abstractMatches = new ArrayList<>();
133	            for (Outcome existing : allOutcomes) {
134	                if (existing.getAbstractText() != null) {
135	                    double similarity = tokenOverlap(abstractText, existing.getAbstractText());
136	                    if (similarity >= 0.70) {
137	                        abstractMatches.add(existing.getId());
138	                    }
139	                }
140	            }
141	            if (!abstractMatches.isEmpty()) {
142	                return DuplicateCheckResponse.builder()
143	                        .duplicateFound(true)
144	                        .matchingOutcomeIds(abstractMatches)
145	                        .reason("High abstract similarity detected (>= 70%)")
146	                        .build();
147	            }
148	        }
149	
150	        return DuplicateCheckResponse.builder()
151	                .duplicateFound(false)
152	                .matchingOutcomeIds(List.of())
153	                .reason(null)
154	                .build();
155	    }
156	
157	    public double tokenOverlap(String a, String b) {
158	        Set<String> tokensA = tokenize(a);
159	        Set<String> tokensB = tokenize(b);
160	        if (tokensA.isEmpty() || tokensB.isEmpty()) return 0.0;
161	
162	        Set<String> intersection = new HashSet<>(tokensA);
163	        intersection.retainAll(tokensB);
164	
165	        Set<String> union = new HashSet<>(tokensA);
166	        union.addAll(tokensB);
167	
168	        return (double) intersection.size() / union.size();
169	    }
170	
171	    private Set<String> tokenize(String text) {
172	        if (text == null) return Set.of();
173	        return Arrays.stream(text.toLowerCase().split("[\\s\\p{Punct}]+"))
174	                .filter(t -> !t.isBlank() && t.length() > 2)
175	                .collect(Collectors.toSet());
176	    }
177	
178	    public String normalizeTitle(String title) {
179	        if (title == null) return "";
180	        return title.toLowerCase()
181	                .replaceAll("[^a-z0-9\\s]", "")
182	                .trim()
183	                .replaceAll("\\s+", " ");
184	    }
185	
186	    public PageResponse<OutcomeResponse> listByProject(UUID projectId, int page, int pageSize) {
187	        var pageable = PageRequest.of(page, pageSize);
188	        return PageResponse.of(outcomeRepository.findByProjectId(projectId, pageable).map(this::toResponse));
189	    }
190	
191	    public OutcomeResponse getOutcome(UUID outcomeId) {
192	        Outcome outcome = outcomeRepository.findById(outcomeId)
193	                .orElseThrow(() -> new AppException("OUTCOME_NOT_FOUND", "Outcome not found", HttpStatus.NOT_FOUND));
194	        return toResponse(outcome);
195	    }
196	
197	    public OutcomeResponse toResponse(Outcome outcome) {
198	        List<ContributionResponse> contribs = contributionRepository.findByOutcomeId(outcome.getId())
199	                .stream().map(c -> ContributionResponse.builder()
200	                        .id(c.getId())
201	                        .contributorUserId(c.getContributorUserId())
202	                        .sharePercent(c.getSharePercent())
203	                        .build())
204	                .collect(Collectors.toList());
205	
206	        return OutcomeResponse.builder()
207	                .id(outcome.getId())
208	                .type(outcome.getType())
209	                .projectId(outcome.getProjectId())
210	                .titleOriginal(outcome.getTitleOriginal())
211	                .status(outcome.getStatus())
212	                .contributions(contribs)
213	                .createdAt(outcome.getCreatedAt())
214	                .build();
215	    }
216	}
