26	@Slf4j
27	@Service
28	@RequiredArgsConstructor
29	public class InteractionService {
30	
31	    private final CommentRepository commentRepository;
32	    private final LikeRepository likeRepository;
33	    private final FavoriteRepository favoriteRepository;
34	    private final ReportRepository reportRepository;
35	    private final ModerationQueueRepository moderationQueueRepository;
36	    private final BlacklistRepository blacklistRepository;
37	    private final OperationalParamRepository operationalParamRepository;
38	    private final AppProperties appProperties;
39	
40	    @Transactional
41	    public CommentResponse createComment(CommentCreateRequest request, UUID userId) {
42	        // Check blacklist
43	        Optional<Blacklist> blacklisted = blacklistRepository.findActiveByUserId(userId, OffsetDateTime.now());
44	        if (blacklisted.isPresent()) {
45	            throw new AppException("USER_BLACKLISTED", "User is blacklisted and cannot post comments", HttpStatus.FORBIDDEN);
46	        }
47	
48	        // Rate limit: 30 comments per hour
49	        OffsetDateTime oneHourAgo = OffsetDateTime.now().minusHours(1);
50	        long recentComments = commentRepository.countByAuthorUserIdAndCreatedAtAfter(userId, oneHourAgo);
51	        int limit = appProperties.getRateLimit().getCommentsPerHour();
52	        if (recentComments >= limit) {
53	            throw new RateLimitException("Comment rate limit exceeded: " + limit + " per hour", 3600L);
54	        }
55	
56	        // Check sensitive words
57	        checkSensitiveWords(request.getText());
58	
59	        Comment comment = Comment.builder()
60	                .authorUserId(userId)
61	                .contentType(request.getContentType())
62	                .contentId(request.getContentId())
63	                .text(request.getText())
64	                .status("ACTIVE")
65	                .build();
66	        comment = commentRepository.save(comment);
67	
68	        return toCommentResponse(comment);
69	    }
70	
71	    @Transactional
72	    public void createLike(LikeRequest request, UUID userId) {
73	        // Upsert: ignore if already liked
74	        Optional<Like> existing = likeRepository.findByUserIdAndContentTypeAndContentId(
75	                userId, request.getContentType(), request.getContentId());
76	        if (existing.isEmpty()) {
77	            Like like = Like.builder()
78	                    .userId(userId)
79	                    .contentType(request.getContentType())
80	                    .contentId(request.getContentId())
81	                    .build();
82	            likeRepository.save(like);
83	        }
84	    }
85	
86	    @Transactional
87	    public void createFavorite(FavoriteRequest request, UUID userId) {
88	        Optional<Favorite> existing = favoriteRepository.findByUserIdAndContentTypeAndContentId(
89	                userId, request.getContentType(), request.getContentId());
90	        if (existing.isEmpty()) {
91	            Favorite favorite = Favorite.builder()
92	                    .userId(userId)
93	                    .contentType(request.getContentType())
94	                    .contentId(request.getContentId())
95	                    .build();
96	            favoriteRepository.save(favorite);
97	        }
98	    }
99	
100	    @Transactional
101	    public void createReport(ReportRequest request, UUID userId) {
102	        // Rate limit: 10 reports per day
103	        OffsetDateTime oneDayAgo = OffsetDateTime.now().minusDays(1);
104	        long recentReports = reportRepository.countByReporterUserIdAndCreatedAtAfter(userId, oneDayAgo);
105	        int limit = appProperties.getRateLimit().getReportsPerDay();
106	        if (recentReports >= limit) {
107	            throw new RateLimitException("Report rate limit exceeded: " + limit + " per day", 86400L);
108	        }
109	
110	        Report report = Report.builder()
111	                .reporterUserId(userId)
112	                .contentType(request.getContentType())
113	                .contentId(request.getContentId())
114	                .reason(request.getReason())
115	                .status("PENDING")
116	                .build();
117	        reportRepository.save(report);
118	
119	        // Add to moderation queue
120	        ModerationQueue mq = ModerationQueue.builder()
121	                .queueType("REPORT")
122	                .targetType(request.getContentType())
123	                .targetId(request.getContentId())
124	                .payload("{\"reason\":\"" + request.getReason().replace("\"", "\\\"") + "\"}")
125	                .status("PENDING")
126	                .build();
127	        moderationQueueRepository.save(mq);
128	    }
129	
130	    public PageResponse<CommentResponse> getComments(String contentType, UUID contentId, int page, int pageSize) {
131	        var commentPage = commentRepository.findByContentTypeAndContentIdOrderByCreatedAtDesc(
132	                contentType, contentId, PageRequest.of(page, pageSize));
133	        return PageResponse.of(commentPage.map(this::toCommentResponse));
134	    }
135	
136	    private void checkSensitiveWords(String text) {
137	        try {
138	            Optional<com.example.ricms.domain.entity.OperationalParam> param =
139	                    operationalParamRepository.findById("sensitive_words");
140	            if (param.isPresent()) {
141	                String valueJson = param.get().getValueJson();
142	                // Parse simple JSON array of strings
143	                if (valueJson != null && valueJson.startsWith("[")) {
144	                    String[] words = valueJson.replaceAll("[\\[\\]\"\\s]", "").split(",");
145	                    String textLower = text.toLowerCase();
146	                    for (String word : words) {
147	                        if (!word.isBlank() && textLower.contains(word.toLowerCase())) {
148	                            throw new AppException("CONTENT_POLICY_VIOLATION",
149	                                    "Comment contains restricted content", HttpStatus.BAD_REQUEST);
150	                        }
151	                    }
152	                }
153	            }
154	        } catch (AppException e) {
155	            throw e;
156	        } catch (Exception e) {
157	            log.warn("Failed to check sensitive words: {}", e.getMessage());
158	        }
159	    }
160	
161	    private CommentResponse toCommentResponse(Comment c) {
162	        return CommentResponse.builder()
163	                .id(c.getId())
164	                .authorUserId(c.getAuthorUserId())
165	                .contentType(c.getContentType())
166	                .contentId(c.getContentId())
167	                .text(c.getText())
168	                .status(c.getStatus())
169	                .createdAt(c.getCreatedAt())
170	                .build();
171	    }
