14	import org.springframework.security.crypto.password.PasswordEncoder;
15	import org.springframework.stereotype.Service;
16	import org.springframework.transaction.annotation.Transactional;
17	
18	import java.util.UUID;
19	
20	@Slf4j
21	@Service
22	@RequiredArgsConstructor
23	public class AuthService {
24	
25	    private final UserRepository userRepository;
26	    private final PasswordEncoder passwordEncoder;
27	    private final JwtUtil jwtUtil;
28	    private final AppProperties appProperties;
29	    private final AuditService auditService;
30	
31	    public AuthResponse login(LoginRequest request) {
32	        User user = userRepository.findByUsername(request.getUsername())
33	                .orElseThrow(() -> new AppException("INVALID_CREDENTIALS", "Invalid username or password", HttpStatus.UNAUTHORIZED));
34	
35	        if (!passwordEncoder.matches(request.getPassword(), user.getPasswordHash())) {
36	            throw new AppException("INVALID_CREDENTIALS", "Invalid username or password", HttpStatus.UNAUTHORIZED);
37	        }
38	
39	        if (user.getStatus().name().equals("SUSPENDED") || user.getStatus().name().equals("DEACTIVATED")) {
40	            throw new AppException("ACCOUNT_DISABLED", "Account is not active", HttpStatus.FORBIDDEN);
41	        }
42	
43	        String token = jwtUtil.generateToken(user.getId(), user.getUsername());
44	        long expiresIn = appProperties.getJwt().getExpirationMs() / 1000;
45	        return new AuthResponse(token, expiresIn);
46	    }
47	
48	    @Transactional
49	    public void rotatePassword(UUID userId, PasswordRotateRequest request) {
50	        User user = userRepository.findById(userId)
51	                .orElseThrow(() -> new AppException("USER_NOT_FOUND", "User not found", HttpStatus.NOT_FOUND));
52	
53	        if (!passwordEncoder.matches(request.getCurrentPassword(), user.getPasswordHash())) {
54	            throw new AppException("INVALID_CREDENTIALS", "Current password is incorrect", HttpStatus.UNAUTHORIZED);
55	        }
56	
57	        user.setPasswordHash(passwordEncoder.encode(request.getNewPassword()));
58	        userRepository.save(user);
59	
60	        auditService.record(userId, "USER", userId.toString(), "PASSWORD_ROTATE", "USER_REQUEST", null, null);
61	    }
62	}
