3	import com.example.ricms.exception.AppException;
4	import org.springframework.http.HttpStatus;
5	import org.springframework.security.core.Authentication;
6	import org.springframework.security.core.context.SecurityContextHolder;
7	
8	import java.util.UUID;
9	
10	public final class SecurityUtils {
11	
12	    private SecurityUtils() {}
13	
14	    public static UUID getCurrentUserId() {
15	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
16	        if (auth == null || !auth.isAuthenticated()) {
17	            throw new AppException("UNAUTHORIZED", "No authenticated user", HttpStatus.UNAUTHORIZED);
18	        }
19	        Object principal = auth.getPrincipal();
20	        if (principal instanceof RicmsPrincipal ricmsPrincipal) {
21	            return ricmsPrincipal.getUserId();
22	        }
23	        throw new AppException("UNAUTHORIZED", "Cannot determine current user", HttpStatus.UNAUTHORIZED);
24	    }
25	
26	    public static String getCurrentUsername() {
27	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
28	        if (auth == null || !auth.isAuthenticated()) {
29	            throw new AppException("UNAUTHORIZED", "No authenticated user", HttpStatus.UNAUTHORIZED);
30	        }
31	        return auth.getName();
32	    }
33	
34	    public static boolean hasRole(String role) {
35	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
36	        if (auth == null) return false;
37	        return auth.getAuthorities().stream()
38	                .anyMatch(a -> a.getAuthority().equals("ROLE_" + role));
39	    }
40	}
