3	import jakarta.servlet.FilterChain;
4	import jakarta.servlet.ServletException;
5	import jakarta.servlet.http.HttpServletRequest;
6	import jakarta.servlet.http.HttpServletResponse;
7	import lombok.RequiredArgsConstructor;
8	import lombok.extern.slf4j.Slf4j;
9	import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
10	import org.springframework.security.core.context.SecurityContextHolder;
11	import org.springframework.security.core.userdetails.UserDetails;
12	import org.springframework.security.web.authentication.WebAuthenticationDetailsSource;
13	import org.springframework.stereotype.Component;
14	import org.springframework.util.StringUtils;
15	import org.springframework.web.filter.OncePerRequestFilter;
16	
17	import java.io.IOException;
18	
19	@Slf4j
20	@Component
21	@RequiredArgsConstructor
22	public class JwtFilter extends OncePerRequestFilter {
23	
24	    private final JwtUtil jwtUtil;
25	    private final UserDetailsServiceImpl userDetailsService;
26	
27	    @Override
28	    protected void doFilterInternal(HttpServletRequest request,
29	                                    HttpServletResponse response,
30	                                    FilterChain filterChain) throws ServletException, IOException {
31	        String token = extractToken(request);
32	        if (token != null && jwtUtil.validateToken(token)) {
33	            String username = jwtUtil.getUsername(token);
34	            UserDetails userDetails = userDetailsService.loadUserByUsername(username);
35	            UsernamePasswordAuthenticationToken auth =
36	                    new UsernamePasswordAuthenticationToken(userDetails, null, userDetails.getAuthorities());
37	            auth.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
38	            SecurityContextHolder.getContext().setAuthentication(auth);
39	        }
40	        filterChain.doFilter(request, response);
41	    }
42	
43	    private String extractToken(HttpServletRequest request) {
44	        String header = request.getHeader("Authorization");
45	        if (StringUtils.hasText(header) && header.startsWith("Bearer ")) {
46	            return header.substring(7);
47	        }
48	        return null;
49	    }
50	}
