14	import org.springframework.data.domain.PageRequest;
15	import org.springframework.http.HttpStatus;
16	import org.springframework.stereotype.Service;
17	import org.springframework.transaction.annotation.Transactional;
18	
19	import java.math.BigDecimal;
20	import java.util.List;
21	import java.util.UUID;
22	
23	@Slf4j
24	@Service
25	@RequiredArgsConstructor
26	public class MemberService {
27	
28	    private final MemberRepository memberRepository;
29	    private final PointsLedgerRepository pointsLedgerRepository;
30	
31	    public MemberResponse getMyProfile(UUID userId) {
32	        Member member = memberRepository.findByUserId(userId)
33	                .orElseThrow(() -> new AppException("MEMBER_NOT_FOUND", "Member profile not found", HttpStatus.NOT_FOUND));
34	        return toResponse(member);
35	    }
36	
37	    public PageResponse<PointsLedgerResponse> getPointsLedger(UUID userId, int page, int pageSize) {
38	        Member member = memberRepository.findByUserId(userId)
39	                .orElseThrow(() -> new AppException("MEMBER_NOT_FOUND", "Member profile not found", HttpStatus.NOT_FOUND));
40	        var ledgerPage = pointsLedgerRepository.findByMemberIdOrderByCreatedAtDesc(
41	                member.getId(), PageRequest.of(page, pageSize));
42	        return PageResponse.of(ledgerPage.map(this::toLedgerResponse));
43	    }
44	
45	    @Transactional
46	    public void accruePoints(UUID memberId, UUID orderId, BigDecimal payableAmount) {
47	        Member member = memberRepository.findById(memberId)
48	                .orElseThrow(() -> new AppException("MEMBER_NOT_FOUND", "Member not found", HttpStatus.NOT_FOUND));
49	
50	        long pointsEarned = payableAmount.longValue(); // 1 point per dollar
51	        PointsLedger ledger = PointsLedger.builder()
52	                .memberId(memberId)
53	                .pointsDelta(pointsEarned)
54	                .sourceOrderId(orderId)
55	                .currencyAmountBasis(payableAmount)
56	                .description("Points earned for order " + orderId)
57	                .build();
58	        pointsLedgerRepository.save(ledger);
59	
60	        member.setPointsBalance(member.getPointsBalance() + pointsEarned);
61	        checkAndUpgradeTier(member);
62	        memberRepository.save(member);
63	    }
64	
65	    public void checkAndUpgradeTier(Member member) {
66	        long balance = member.getPointsBalance();
67	        MemberTier newTier;
68	        if (balance >= 5000) {
69	            newTier = MemberTier.GOLD;
70	        } else if (balance >= 1000) {
71	            newTier = MemberTier.SILVER;
72	        } else {
73	            newTier = MemberTier.BRONZE;
74	        }
75	        if (newTier.ordinal() > member.getTier().ordinal()) {
76	            log.info("Upgrading member {} tier from {} to {}", member.getId(), member.getTier(), newTier);
77	            member.setTier(newTier);
78	        }
79	    }
80	
81	    @Transactional
82	    public void monthlyTierDowngrade() {
83	        log.info("Running monthly tier downgrade job");
84	        List<Member> allMembers = memberRepository.findAll();
85	        for (Member member : allMembers) {
86	            Long totalPoints = pointsLedgerRepository.sumPointsByMemberId(member.getId());
87	            if (totalPoints == null) totalPoints = 0L;
88	
89	            MemberTier correctTier;
90	            if (totalPoints >= 5000) {
91	                correctTier = MemberTier.GOLD;
92	            } else if (totalPoints >= 1000) {
93	                correctTier = MemberTier.SILVER;
94	            } else {
95	                correctTier = MemberTier.BRONZE;
96	            }
97	            member.setTier(correctTier);
98	            member.setPointsBalance(totalPoints);
99	        }
100	        memberRepository.saveAll(allMembers);
101	    }
102	
103	    public MemberResponse toResponse(Member member) {
104	        return MemberResponse.builder()
105	                .memberId(member.getId())
106	                .userId(member.getUserId())
107	                .status(member.getStatus())
108	                .tier(member.getTier())
109	                .pointsBalance(member.getPointsBalance())
110	                .build();
111	    }
112	
113	    private PointsLedgerResponse toLedgerResponse(PointsLedger p) {
114	        return PointsLedgerResponse.builder()
115	                .id(p.getId())
116	                .pointsDelta(p.getPointsDelta())
117	                .sourceOrderId(p.getSourceOrderId())
118	                .currencyAmountBasis(p.getCurrencyAmountBasis())
119	                .description(p.getDescription())
120	                .createdAt(p.getCreatedAt())
121	                .build();
122	    }
123	}
