4	import com.example.ricms.domain.entity.Coupon;
5	import com.example.ricms.domain.entity.Member;
6	import com.example.ricms.domain.enums.CouponType;
7	import com.example.ricms.dto.response.PricingResult;
8	import com.example.ricms.repository.CampaignRepository;
9	import com.example.ricms.repository.CouponRepository;
10	import com.example.ricms.repository.MemberRepository;
11	import lombok.RequiredArgsConstructor;
12	import lombok.extern.slf4j.Slf4j;
13	import org.springframework.stereotype.Service;
14	
15	import java.math.BigDecimal;
16	import java.math.RoundingMode;
17	import java.time.OffsetDateTime;
18	import java.util.List;
19	import java.util.Optional;
20	import java.util.UUID;
21	
22	@Slf4j
23	@Service
24	@RequiredArgsConstructor
25	public class PricingEngine {
26	
27	    private final CouponRepository couponRepository;
28	    private final CampaignRepository campaignRepository;
29	    private final MemberRepository memberRepository;
30	
31	    public PricingResult computePricing(UUID buyerId, BigDecimal subtotal, BigDecimal shippingCost,
32	                                        String couponCode, UUID campaignId) {
33	        BigDecimal discounts = BigDecimal.ZERO;
34	        BigDecimal finalShipping = shippingCost != null ? shippingCost : BigDecimal.ZERO;
35	        UUID appliedCouponId = null;
36	        UUID appliedCampaignId = null;
37	
38	        OffsetDateTime now = OffsetDateTime.now();
39	
40	        // 1. Apply campaign discount (if member in good standing)
41	        if (campaignId != null && buyerId != null) {
42	            Optional<Campaign> campOpt = campaignRepository.findById(campaignId);
43	            if (campOpt.isPresent()) {
44	                Campaign campaign = campOpt.get();
45	                if (campaign.isActive() &&
46	                    (campaign.getActiveFrom() == null || campaign.getActiveFrom().isBefore(now)) &&
47	                    (campaign.getActiveTo() == null || campaign.getActiveTo().isAfter(now))) {
48	                    BigDecimal campaignDiscount = computeCampaignDiscount(campaign, subtotal);
49	                    if (campaignDiscount.compareTo(BigDecimal.ZERO) > 0) {
50	                        discounts = discounts.add(campaignDiscount);
51	                        appliedCampaignId = campaignId;
52	                    }
53	                }
54	            }
55	        }
56	
57	        // 2. Apply coupon
58	        if (couponCode != null && !couponCode.isBlank()) {
59	            Optional<Coupon> couponOpt = couponRepository.findByCode(couponCode.toUpperCase().trim());
60	            if (couponOpt.isPresent()) {
61	                Coupon coupon = couponOpt.get();
62	                if (coupon.isActive() &&
63	                    (coupon.getActiveFrom() == null || coupon.getActiveFrom().isBefore(now)) &&
64	                    (coupon.getActiveTo() == null || coupon.getActiveTo().isAfter(now))) {
65	                    if (coupon.getType() == CouponType.SHIPPING_WAIVER) {
66	                        // Shipping waiver
67	                        if (coupon.getThresholdAmount() == null ||
68	                            subtotal.compareTo(coupon.getThresholdAmount()) >= 0) {
69	                            finalShipping = BigDecimal.ZERO;
70	                            appliedCouponId = coupon.getId();
71	                        }
72	                    } else if (coupon.getType() == CouponType.THRESHOLD_DISCOUNT) {
73	                        if (coupon.getThresholdAmount() == null ||
74	                            subtotal.compareTo(coupon.getThresholdAmount()) >= 0) {
75	                            BigDecimal couponDiscount = coupon.getDiscountAmount() != null
76	                                    ? coupon.getDiscountAmount() : BigDecimal.ZERO;
77	                            discounts = discounts.add(couponDiscount);
78	                            appliedCouponId = coupon.getId();
79	                        }
80	                    } else if (coupon.getType() == CouponType.PERCENTAGE_DISCOUNT) {
81	                        BigDecimal pct = coupon.getDiscountPercent() != null
82	                                ? coupon.getDiscountPercent() : BigDecimal.ZERO;
83	                        BigDecimal couponDiscount = subtotal.multiply(pct).divide(BigDecimal.valueOf(100), 2, RoundingMode.HALF_UP);
84	                        if (coupon.getMaxDiscountAmount() != null && couponDiscount.compareTo(coupon.getMaxDiscountAmount()) > 0) {
85	                            couponDiscount = coupon.getMaxDiscountAmount();
86	                        }
87	                        discounts = discounts.add(couponDiscount);
88	                        appliedCouponId = coupon.getId();
89	                    }
90	                }
91	            }
92	        }
93	
94	        // Ensure discounts don't exceed subtotal
95	        if (discounts.compareTo(subtotal) > 0) {
96	            discounts = subtotal;
97	        }
98	
99	        BigDecimal finalSubtotal = subtotal.subtract(discounts);
100	        if (finalSubtotal.compareTo(BigDecimal.ZERO) < 0) finalSubtotal = BigDecimal.ZERO;
101	        BigDecimal totalPayable = finalSubtotal.add(finalShipping);
102	
103	        return PricingResult.builder()
104	                .finalSubtotal(finalSubtotal)
105	                .discountsTotal(discounts)
106	                .shippingTotal(finalShipping)
107	                .totalPayable(totalPayable)
108	                .appliedCouponId(appliedCouponId)
109	                .appliedCampaignId(appliedCampaignId)
110	                .build();
111	    }
112	
113	    private BigDecimal computeCampaignDiscount(Campaign campaign, BigDecimal subtotal) {
114	        try {
115	            String params = campaign.getParams();
116	            if (params == null) return BigDecimal.ZERO;
117	
118	            switch (campaign.getType()) {
119	                case SPEND_AND_GET: {
120	                    // {"spendThreshold": 1000, "rewardAmount": 200}
121	                    double threshold = extractDoubleParam(params, "spendThreshold");
122	                    double reward = extractDoubleParam(params, "rewardAmount");
123	                    if (subtotal.compareTo(BigDecimal.valueOf(threshold)) >= 0) {
124	                        return BigDecimal.valueOf(reward);
125	                    }
126	                    break;
127	                }
128	                case SECOND_ITEM_DISCOUNT: {
129	                    // {"discountPercent": 50} - applied as a percentage of subtotal for simplicity
130	                    double pct = extractDoubleParam(params, "discountPercent");
131	                    return subtotal.multiply(BigDecimal.valueOf(pct / 100)).setScale(2, RoundingMode.HALF_UP);
132	                }
133	            }
134	        } catch (Exception e) {
135	            log.warn("Failed to compute campaign discount: {}", e.getMessage());
136	        }
137	        return BigDecimal.ZERO;
138	    }
139	
140	    private double extractDoubleParam(String json, String key) {
141	        // Simple extraction without full JSON parsing
142	        int idx = json.indexOf("\"" + key + "\"");
143	        if (idx < 0) idx = json.indexOf(key);
144	        if (idx < 0) return 0;
145	        int colonIdx = json.indexOf(":", idx);
146	        if (colonIdx < 0) return 0;
147	        int start = colonIdx + 1;
148	        while (start < json.length() && (json.charAt(start) == ' ' || json.charAt(start) == '\t')) start++;
149	        int end = start;
150	        while (end < json.length() && (Character.isDigit(json.charAt(end)) || json.charAt(end) == '.')) end++;
151	        if (start == end) return 0;
152	        return Double.parseDouble(json.substring(start, end));
153	    }
154	}
