49	    @Transactional
50	    public OrderResponse placeOrder(PlaceOrderRequest request, String idempotencyKey) {
51	        permissionEnforcer.require("ORDER", "WRITE");
52	        // Check idempotency
53	        if (idempotencyKey != null && !idempotencyKey.isBlank()) {
54	            String keyHash = hashIdempotencyKey(request.getBuyerId(), idempotencyKey);
55	            Optional<Order> existing = orderRepository.findByBuyerUserIdAndIdempotencyKeyHash(
56	                    request.getBuyerId(), keyHash);
57	            if (existing.isPresent()) {
58	                Order existingOrder = existing.get();
59	                if (existingOrder.getCreatedAt().isAfter(OffsetDateTime.now().minusMinutes(10))) {
60	                    return toResponse(existingOrder);
61	                }
62	            }
63	        }
64	
65	        // Compute subtotal
66	        BigDecimal subtotal = request.getItems().stream()
67	                .map(item -> item.getUnitPrice().multiply(BigDecimal.valueOf(item.getQuantity())))
68	                .reduce(BigDecimal.ZERO, BigDecimal::add);
69	
70	        BigDecimal shippingCost = computeShipping(request.getShippingCountry());
71	
72	        // Pricing
73	        PricingResult pricing = pricingEngine.computePricing(
74	                request.getBuyerId(), subtotal, shippingCost,
75	                request.getCouponCode(), request.getCampaignId());
76	
77	        // Reserve inventory
78	        for (var item : request.getItems()) {
79	            Inventory inv = inventoryRepository.findBySkuWithLock(item.getSku())
80	                    .orElseThrow(() -> new AppException("INVENTORY_NOT_FOUND",
81	                            "SKU not found: " + item.getSku(), HttpStatus.BAD_REQUEST));
82	            int available = inv.getOnHand() - inv.getReserved();
83	            if (available < item.getQuantity()) {
84	                throw new AppException("INSUFFICIENT_INVENTORY",
85	                        "Insufficient inventory for SKU: " + item.getSku(), HttpStatus.CONFLICT);
86	            }
87	            inv.setReserved(inv.getReserved() + item.getQuantity());
88	            inv.setReservedUntil(OffsetDateTime.now().plusMinutes(30));
89	            inventoryRepository.save(inv);
90	        }
91	
92	        // Create order
93	        String orderNumber = "ORD-" + System.currentTimeMillis() + "-" + orderSeq.incrementAndGet();
94	        String idempotencyKeyHash = idempotencyKey != null ?
95	                hashIdempotencyKey(request.getBuyerId(), idempotencyKey) : null;
96	
97	        Order order = Order.builder()
98	                .orderNumber(orderNumber)
99	                .buyerUserId(request.getBuyerId())
100	                .status(OrderStatus.PLACED)
101	                .subtotal(subtotal)
102	                .discountsTotal(pricing.getDiscountsTotal())
103	                .shippingTotal(pricing.getShippingTotal())
104	                .totalPayable(pricing.getTotalPayable())
105	                .couponId(pricing.getAppliedCouponId())
106	                .campaignId(pricing.getAppliedCampaignId())
107	                .paymentMethod(request.getPaymentMethod())
108	                .shippingCountry(request.getShippingCountry())
109	                .shippingPostalCode(request.getShippingPostalCode())
110	                .idempotencyKeyHash(idempotencyKeyHash)
111	                .items(new ArrayList<>())
112	                .build();
113	
114	        order = orderRepository.save(order);
115	
116	        // Create items
117	        List<OrderItem> items = new ArrayList<>();
118	        for (var itemDto : request.getItems()) {
119	            OrderItem item = OrderItem.builder()
120	                    .orderId(order.getId())
121	                    .sku(itemDto.getSku())
122	                    .quantity(itemDto.getQuantity())
123	                    .unitPrice(itemDto.getUnitPrice())
124	                    .lineTotal(itemDto.getUnitPrice().multiply(BigDecimal.valueOf(itemDto.getQuantity())))
125	                    .build();
126	            items.add(orderItemRepository.save(item));
127	        }
128	        order.setItems(items);
129	
130	        auditService.record(request.getBuyerId(), "ORDER", order.getId().toString(),
131	                "PLACE_ORDER", "USER_ACTION", null, orderNumber);
132	
133	        return toResponse(order);
134	    }
