65	                }
66	            }
67	        }
68	
69	        // Compute subtotal
70	        BigDecimal subtotal = request.getItems().stream()
71	                .map(item -> item.getUnitPrice().multiply(BigDecimal.valueOf(item.getQuantity())))
72	                .reduce(BigDecimal.ZERO, BigDecimal::add);
73	
74	        BigDecimal shippingCost = computeShipping(request.getShippingCountry());
75	
76	        // Pricing
77	        PricingResult pricing = pricingEngine.computePricing(
78	                request.getBuyerId(), subtotal, shippingCost,
79	                request.getCouponCode(), request.getCampaignId());
80	
81	        // All-or-nothing inventory reservation (Q9):
82	        // Pass 1 — acquire pessimistic locks and verify ALL items are available before
83	        //           touching any reserved count. Use a LinkedHashMap to preserve order
84	        //           and deduplicate SKUs (aggregate quantities for duplicate SKU entries).
85	        Map<String, Integer> skuQuantities = new LinkedHashMap<>();
86	        for (var item : request.getItems()) {
87	            skuQuantities.merge(item.getSku(), item.getQuantity(), Integer::sum);
88	        }
89	
