229	        List<String> insufficientSkus = new ArrayList<>();
230	        for (Map.Entry<String, Integer> entry : skuQuantities.entrySet()) {
231	            Inventory inv = inventoryRepository.findBySkuWithLock(entry.getKey())
232	                    .orElse(null);
233	            if (inv == null || inv.getReserved() < entry.getValue()) {
234	                insufficientSkus.add(entry.getKey());
235	            }
236	        }
237	        if (!insufficientSkus.isEmpty()) {
238	            throw new AppException("FULFILLMENT_INVENTORY_INSUFFICIENT",
239	                    "Cannot fulfill: insufficient reserved inventory for SKU(s): " +
240	                    String.join(", ", insufficientSkus),
241	                    HttpStatus.UNPROCESSABLE_ENTITY);
242	        }
243	
244	        order.setStatus(OrderStatus.FULFILLMENT_RESERVED);
245	        orderRepository.save(order);
246	        return toResponse(order);
247	    }
