347	    private BigDecimal computeShipping(String country) {
348	        // Simple flat rate
349	        if ("US".equalsIgnoreCase(country)) return BigDecimal.valueOf(10.00);
350	        if (country == null) return BigDecimal.valueOf(15.00);
351	        return BigDecimal.valueOf(25.00);
352	    }
