23	@Slf4j
24	@Service
25	@RequiredArgsConstructor
26	public class OutcomeService {
27	
28	    private final OutcomeRepository outcomeRepository;
29	    private final ContributionRepository contributionRepository;
30	    private final OutcomeEvidenceRepository outcomeEvidenceRepository;
31	    private final ModerationQueueRepository moderationQueueRepository;
32	    private final AuditService auditService;
33	    private final PermissionEnforcer permissionEnforcer;
34	
35	    @Transactional
36	    public OutcomeResponse registerOutcome(OutcomeCreateRequest request, UUID actorId) {
37	        permissionEnforcer.require("OUTCOME", "WRITE");
38	        // Validate contributions sum to 100%
39	        if (request.getContributions() == null || request.getContributions().isEmpty()) {
40	            throw new AppException("INVALID_CONTRIBUTIONS", "At least one contribution is required", HttpStatus.BAD_REQUEST);
41	        }
42	        BigDecimal totalShare = request.getContributions().stream()
43	                .map(c -> c.getSharePercent() != null ? c.getSharePercent() : BigDecimal.ZERO)
44	                .reduce(BigDecimal.ZERO, BigDecimal::add);
45	        if (totalShare.compareTo(new BigDecimal("100.00")) != 0) {
46	            throw new AppException("INVALID_CONTRIBUTIONS",
47	                    "Contributions must sum to exactly 100%, got: " + totalShare, HttpStatus.BAD_REQUEST);
48	        }
49	
50	        // Normalize title
51	        String titleNormalized = normalizeTitle(request.getTitle());
52	
53	        // Check certificate uniqueness
54	        if (request.getCertificateNumber() != null && !request.getCertificateNumber().isBlank()) {
55	            outcomeRepository.findByCertificateNumber(request.getCertificateNumber())
56	                    .ifPresent(existing -> {
57	                        throw new AppException("DUPLICATE_CERTIFICATE",
58	                                "Certificate number already exists", HttpStatus.CONFLICT);
59	                    });
60	        }
61	
62	        // Check for duplicates
63	        DuplicateCheckResponse dupCheck = checkDuplicateInternal(titleNormalized, request.getAbstractText());
64	        String status = dupCheck.isDuplicateFound() ? "UNDER_REVIEW" : "ACTIVE";
65	
66	        Outcome outcome = Outcome.builder()
67	                .type(request.getType())
68	                .projectId(request.getProjectId())
69	                .titleOriginal(request.getTitle())
70	                .titleNormalized(titleNormalized)
71	                .abstractText(request.getAbstractText())
72	                .certificateNumber(request.getCertificateNumber())
73	                .status(status)
74	                .build();
75	        outcome = outcomeRepository.save(outcome);
76	
77	        // Save contributions
78	        for (var contribDto : request.getContributions()) {
79	            Contribution c = Contribution.builder()
80	                    .outcomeId(outcome.getId())
81	                    .contributorUserId(contribDto.getContributorId())
82	                    .sharePercent(contribDto.getSharePercent())
83	                    .build();
84	            contributionRepository.save(c);
85	        }
86	
87	        // Save evidences
88	        if (request.getEvidences() != null) {
89	            for (var evDto : request.getEvidences()) {
90	                OutcomeEvidence ev = OutcomeEvidence.builder()
91	                        .outcomeId(outcome.getId())
92	                        .evidenceType(evDto.getEvidenceType())
93	                        .blobRef(evDto.getBlobRef())
94	                        .build();
95	                outcomeEvidenceRepository.save(ev);
96	            }
97	        }
98	
99	        // If duplicate suspected, add to moderation queue
100	        if (dupCheck.isDuplicateFound()) {
101	            ModerationQueue mq = ModerationQueue.builder()
102	                    .queueType("DUPLICATE_REVIEW")
103	                    .targetType("OUTCOME")
104	                    .targetId(outcome.getId())
105	                    .payload("{\"reason\":\"" + dupCheck.getReason() + "\"}")
106	                    .status("PENDING")
107	                    .build();
108	            moderationQueueRepository.save(mq);
109	        }
110	
111	        auditService.record(actorId, "OUTCOME", outcome.getId().toString(),
112	                "REGISTER", "USER_ACTION", null, outcome.getTitleOriginal());
113	
114	        return toResponse(outcome);
115	    }
116	
117	    public DuplicateCheckResponse checkDuplicate(OutcomeCreateRequest request) {
118	        permissionEnforcer.require("OUTCOME", "READ");
119	        String normalized = normalizeTitle(request.getTitle());
120	        return checkDuplicateInternal(normalized, request.getAbstractText());
121	    }
122	
123	    private DuplicateCheckResponse checkDuplicateInternal(String titleNormalized, String abstractText) {
124	        List<Outcome> exactMatches = outcomeRepository.findByTitleNormalized(titleNormalized);
125	        if (!exactMatches.isEmpty()) {
126	            return DuplicateCheckResponse.builder()
127	                    .duplicateFound(true)
128	                    .matchingOutcomeIds(exactMatches.stream().map(Outcome::getId).collect(Collectors.toList()))
129	                    .reason("Exact title match found")
130	                    .build();
131	        }
132	
133	        // Check abstract token overlap
134	        if (abstractText != null && !abstractText.isBlank()) {
135	            List<Outcome> allOutcomes = outcomeRepository.findAll();
136	            List<UUID> abstractMatches = new ArrayList<>();
137	            for (Outcome existing : allOutcomes) {
138	                if (existing.getAbstractText() != null) {
139	                    double similarity = tokenOverlap(abstractText, existing.getAbstractText());
140	                    if (similarity >= 0.70) {
141	                        abstractMatches.add(existing.getId());
142	                    }
143	                }
144	            }
145	            if (!abstractMatches.isEmpty()) {
146	                return DuplicateCheckResponse.builder()
147	                        .duplicateFound(true)
148	                        .matchingOutcomeIds(abstractMatches)
149	                        .reason("High abstract similarity detected (>= 70%)")
150	                        .build();
151	            }
152	        }
153	
154	        return DuplicateCheckResponse.builder()
155	                .duplicateFound(false)
156	                .matchingOutcomeIds(List.of())
157	                .reason(null)
158	                .build();
159	    }
160	
161	    public double tokenOverlap(String a, String b) {
162	        Set<String> tokensA = tokenize(a);
163	        Set<String> tokensB = tokenize(b);
164	        if (tokensA.isEmpty() || tokensB.isEmpty()) return 0.0;
165	
166	        Set<String> intersection = new HashSet<>(tokensA);
167	        intersection.retainAll(tokensB);
168	
169	        Set<String> union = new HashSet<>(tokensA);
170	        union.addAll(tokensB);
171	
172	        return (double) intersection.size() / union.size();
173	    }
174	
175	    private Set<String> tokenize(String text) {
176	        if (text == null) return Set.of();
177	        return Arrays.stream(text.toLowerCase().split("[\\s\\p{Punct}]+"))
178	                .filter(t -> !t.isBlank() && t.length() > 2)
179	                .collect(Collectors.toSet());
180	    }
181	
182	    public String normalizeTitle(String title) {
183	        if (title == null) return "";
184	        return title.toLowerCase()
185	                .replaceAll("[^a-z0-9\\s]", "")
186	                .trim()
187	                .replaceAll("\\s+", " ");
188	    }
