191	        permissionEnforcer.require("OUTCOME", "READ");
192	        var pageable = PageRequest.of(page, pageSize);
193	        return PageResponse.of(outcomeRepository.findByProjectId(projectId, pageable).map(this::toResponse));
194	    }
