196	    public OutcomeResponse getOutcome(UUID outcomeId) {
197	        permissionEnforcer.require("OUTCOME", "READ");
198	        Outcome outcome = outcomeRepository.findById(outcomeId)
199	                .orElseThrow(() -> new AppException("OUTCOME_NOT_FOUND", "Outcome not found", HttpStatus.NOT_FOUND));
200	        return toResponse(outcome);
201	    }
202	
203	    public OutcomeResponse toResponse(Outcome outcome) {
204	        List<ContributionResponse> contribs = contributionRepository.findByOutcomeId(outcome.getId())
205	                .stream().map(c -> ContributionResponse.builder()
206	                        .id(c.getId())
207	                        .contributorUserId(c.getContributorUserId())
208	                        .sharePercent(c.getSharePercent())
209	                        .build())
210	                .collect(Collectors.toList());
211	
212	        return OutcomeResponse.builder()
213	                .id(outcome.getId())
214	                .type(outcome.getType())
215	                .projectId(outcome.getProjectId())
216	                .titleOriginal(outcome.getTitleOriginal())
217	                .status(outcome.getStatus())
218	                .contributions(contribs)
219	                .createdAt(outcome.getCreatedAt())
220	                .build();
221	    }
