183	                                                    UUID technicianId, String statusStr) {
184	        WorkOrderStatus status = null;
185	        if (statusStr != null && !statusStr.isBlank()) {
186	            try { status = WorkOrderStatus.valueOf(statusStr); } catch (Exception e) { /* ignore */ }
187	        }
188	        OffsetDateTime fromDt = from != null
189	                ? from.atStartOfDay().atOffset(ZoneOffset.UTC)
190	                : OffsetDateTime.now().minusYears(10);
191	        OffsetDateTime toDt = to != null
192	                ? to.plusDays(1).atStartOfDay().atOffset(ZoneOffset.UTC)
193	                : OffsetDateTime.now().plusDays(1);
194	
195	        List<WorkOrder> orders = workOrderRepository.findForAnalytics(technicianId, status, fromDt, toDt);
196	
197	        long submitted = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.SUBMITTED).count();
198	        long assigned = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.ASSIGNED).count();
199	        long inProgress = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.IN_PROGRESS).count();
200	        long resolved = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.RESOLVED).count();
201	        long closed = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.CLOSED).count();
202	
203	        double avgRating = orders.stream()
204	                .mapToInt(w -> workOrderRatingRepository.findByWorkOrderId(w.getId())
205	                        .map(WorkOrderRating::getRating).orElse(0))
206	                .filter(r -> r > 0)
207	                .average().orElse(0.0);
