215	                .map(w -> workOrderCostRepository.findByWorkOrderId(w.getId())
216	                        .map(WorkOrderCost::getLaborCost).orElse(BigDecimal.ZERO))
217	                .reduce(BigDecimal.ZERO, BigDecimal::add);
