219	        return WorkOrderAnalyticsResponse.builder()
220	                .total(orders.size())
221	                .submitted(submitted)
222	                .assigned(assigned)
223	                .inProgress(inProgress)
224	                .resolved(resolved)
225	                .closed(closed)
226	                .avgRating(avgRating)
227	                .totalPartsCost(totalParts)
228	                .totalLaborCost(totalLabor)
229	                .build();
