42	    @Transactional
43	    public CommentResponse createComment(CommentCreateRequest request, UUID userId) {
44	        permissionEnforcer.require("INTERACTION", "WRITE");
45	        // Check blacklist
46	        Optional<Blacklist> blacklisted = blacklistRepository.findActiveByUserId(userId, OffsetDateTime.now());
47	        if (blacklisted.isPresent()) {
48	            throw new AppException("USER_BLACKLISTED", "User is blacklisted and cannot post comments", HttpStatus.FORBIDDEN);
49	        }
50	
51	        // Rate limit: 30 comments per hour
52	        OffsetDateTime oneHourAgo = OffsetDateTime.now().minusHours(1);
53	        long recentComments = commentRepository.countByAuthorUserIdAndCreatedAtAfter(userId, oneHourAgo);
54	        int limit = appProperties.getRateLimit().getCommentsPerHour();
55	        if (recentComments >= limit) {
56	            throw new RateLimitException("Comment rate limit exceeded: " + limit + " per hour", 3600L);
57	        }
58	
59	        // Check sensitive words
60	        checkSensitiveWords(request.getText());
61	
62	        Comment comment = Comment.builder()
63	                .authorUserId(userId)
64	                .contentType(request.getContentType())
65	                .contentId(request.getContentId())
66	                .text(request.getText())
67	                .status("ACTIVE")
68	                .build();
69	        comment = commentRepository.save(comment);
70	
71	        return toCommentResponse(comment);
72	    }
