76	        permissionEnforcer.require("INTERACTION", "WRITE");
77	        // Upsert: ignore if already liked
78	        Optional<Like> existing = likeRepository.findByUserIdAndContentTypeAndContentId(
79	                userId, request.getContentType(), request.getContentId());
80	        if (existing.isEmpty()) {
81	            Like like = Like.builder()
82	                    .userId(userId)
83	                    .contentType(request.getContentType())
84	                    .contentId(request.getContentId())
85	                    .build();
86	            likeRepository.save(like);
87	        }
88	    }
