94	                userId, request.getContentType(), request.getContentId());
95	        if (existing.isEmpty()) {
96	            Favorite favorite = Favorite.builder()
97	                    .userId(userId)
98	                    .contentType(request.getContentType())
99	                    .contentId(request.getContentId())
100	                    .build();
