106	    public void createReport(ReportRequest request, UUID userId) {
107	        permissionEnforcer.require("INTERACTION", "WRITE");
108	        // Rate limit: 10 reports per day
109	        OffsetDateTime oneDayAgo = OffsetDateTime.now().minusDays(1);
110	        long recentReports = reportRepository.countByReporterUserIdAndCreatedAtAfter(userId, oneDayAgo);
111	        int limit = appProperties.getRateLimit().getReportsPerDay();
112	        if (recentReports >= limit) {
113	            throw new RateLimitException("Report rate limit exceeded: " + limit + " per day", 86400L);
114	        }
115	
116	        Report report = Report.builder()
117	                .reporterUserId(userId)
118	                .contentType(request.getContentType())
119	                .contentId(request.getContentId())
120	                .reason(request.getReason())
121	                .status("PENDING")
122	                .build();
123	        reportRepository.save(report);
124	
125	        // Add to moderation queue
126	        ModerationQueue mq = ModerationQueue.builder()
127	                .queueType("REPORT")
128	                .targetType(request.getContentType())
129	                .targetId(request.getContentId())
130	                .payload("{\"reason\":\"" + request.getReason().replace("\"", "\\\"") + "\"}")
131	                .status("PENDING")
132	                .build();
133	        moderationQueueRepository.save(mq);
134	    }
