142	    private void checkSensitiveWords(String text) {
143	        try {
144	            Optional<com.example.ricms.domain.entity.OperationalParam> param =
145	                    operationalParamRepository.findById("sensitive_words");
146	            if (param.isPresent()) {
147	                String valueJson = param.get().getValueJson();
148	                // Parse simple JSON array of strings
149	                if (valueJson != null && valueJson.startsWith("[")) {
150	                    String[] words = valueJson.replaceAll("[\\[\\]\"\\s]", "").split(",");
151	                    String textLower = text.toLowerCase();
152	                    for (String word : words) {
153	                        if (!word.isBlank() && textLower.contains(word.toLowerCase())) {
154	                            throw new AppException("CONTENT_POLICY_VIOLATION",
155	                                    "Comment contains restricted content", HttpStatus.BAD_REQUEST);
156	                        }
157	                    }
158	                }
159	            }
160	        } catch (AppException e) {
161	            throw e;
162	        } catch (Exception e) {
163	            log.warn("Failed to check sensitive words: {}", e.getMessage());
164	        }
165	    }
