168	        return CommentResponse.builder()
169	                .id(c.getId())
170	                .authorUserId(c.getAuthorUserId())
171	                .contentType(c.getContentType())
172	                .contentId(c.getContentId())
173	                .text(c.getText())
174	                .status(c.getStatus())
175	                .createdAt(c.getCreatedAt())
176	                .build();
177	    }
178	}
