1	package com.example.ricms.service;
2	
3	import com.example.ricms.repository.OperationalParamRepository;
4	import lombok.RequiredArgsConstructor;
5	import org.springframework.stereotype.Service;
6	
7	import java.time.LocalTime;
8	import java.time.OffsetDateTime;
9	import java.time.ZoneOffset;
10	
11	@Service
12	@RequiredArgsConstructor
13	public class SlaService {
14	
15	    private final OperationalParamRepository operationalParamRepository;
16	
17	    private static final LocalTime BUSINESS_START = LocalTime.of(9, 0);
18	    private static final LocalTime BUSINESS_END = LocalTime.of(17, 0);
19	
20	    public OffsetDateTime computeFirstResponseDue(OffsetDateTime from) {
21	        int hours = getParamInt("sla_first_response_hours", 4);
22	        return addBusinessHours(from, hours);
23	    }
24	
25	    public OffsetDateTime computeResolutionDue(OffsetDateTime from) {
26	        int days = getParamInt("sla_resolution_days", 3);
27	        return addBusinessDays(from, days);
28	    }
29	
30	    private int getParamInt(String key, int defaultVal) {
31	        try {
32	            return operationalParamRepository.findById(key)
33	                    .map(p -> Integer.parseInt(p.getValueJson().replaceAll("\"", "")))
34	                    .orElse(defaultVal);
35	        } catch (Exception e) {
36	            return defaultVal;
37	        }
38	    }
39	
40	    private OffsetDateTime addBusinessHours(OffsetDateTime from, int hoursToAdd) {
41	        OffsetDateTime current = from;
42	        int hoursAdded = 0;
43	
44	        while (hoursAdded < hoursToAdd) {
45	            // Skip weekends
46	            if (isWeekend(current)) {
47	                current = current.plusDays(1).withHour(9).withMinute(0).withSecond(0).withNano(0);
48	                continue;
49	            }
50	            // If before business hours, advance to start
51	            if (current.toLocalTime().isBefore(BUSINESS_START)) {
52	                current = current.withHour(9).withMinute(0).withSecond(0).withNano(0);
53	            }
54	            // If at or after business end, advance to next business day start
55	            if (!current.toLocalTime().isBefore(BUSINESS_END)) {
56	                current = current.plusDays(1).withHour(9).withMinute(0).withSecond(0).withNano(0);
57	                continue;
58	            }
59	            // Add one hour
60	            current = current.plusHours(1);
61	            hoursAdded++;
62	        }
63	        return current;
64	    }
65	
66	    private OffsetDateTime addBusinessDays(OffsetDateTime from, int daysToAdd) {
67	        OffsetDateTime current = from;
68	        int daysAdded = 0;
69	
70	        while (daysAdded < daysToAdd) {
71	            current = current.plusDays(1);
72	            if (!isWeekend(current)) {
73	                daysAdded++;
74	            }
75	        }
76	        return current.withHour(17).withMinute(0).withSecond(0).withNano(0);
77	    }
78	
79	    private boolean isWeekend(OffsetDateTime dt) {
80	        var dow = dt.getDayOfWeek();
81	        return dow == java.time.DayOfWeek.SATURDAY || dow == java.time.DayOfWeek.SUNDAY;
82	    }
83	}
