15	import org.springframework.data.domain.PageRequest;
16	import org.springframework.http.HttpStatus;
17	import org.springframework.stereotype.Service;
18	import org.springframework.transaction.annotation.Transactional;
19	
20	import java.math.BigDecimal;
21	import java.math.RoundingMode;
22	import java.time.OffsetDateTime;
23	import java.util.List;
24	import java.util.Optional;
25	import java.util.UUID;
26	
27	@Slf4j
28	@Service
29	@RequiredArgsConstructor
30	public class MemberService {
31	
32	    private final MemberRepository memberRepository;
33	    private final PointsLedgerRepository pointsLedgerRepository;
34	
35	    // ------------------------------------------------------------------
36	    // Profile & ledger (Q3 / Q4)
37	    // ------------------------------------------------------------------
38	
39	    public MemberResponse getMyProfile(UUID userId) {
40	        Member member = requireByUserId(userId);
41	        return toResponse(member);
42	    }
43	
44	    public PageResponse<PointsLedgerResponse> getPointsLedger(UUID userId, int page, int pageSize) {
45	        Member member = requireByUserId(userId);
46	        var ledgerPage = pointsLedgerRepository.findByMemberIdOrderByCreatedAtDesc(
47	                member.getId(), PageRequest.of(page, pageSize));
48	        return PageResponse.of(ledgerPage.map(this::toLedgerResponse));
49	    }
50	
51	    // ------------------------------------------------------------------
52	    // Points accrual (Q4)
53	    // Points = floor(totalPayable) — 1 point per whole dollar after discounts.
54	    // Only persisted; the caller (OrderService) is responsible for calling
55	    // this at CONFIRMED_PAYMENT / COMPLETED state.
56	    // ------------------------------------------------------------------
57	
58	    @Transactional
59	    public void accruePoints(UUID memberId, UUID orderId, BigDecimal payableAmount) {
60	        Member member = memberRepository.findById(memberId)
61	                .orElseThrow(() -> new AppException("MEMBER_NOT_FOUND", "Member not found", HttpStatus.NOT_FOUND));
62	
63	        // 1 point per $1.00 – floor to the nearest whole dollar (Q4)
64	        long pointsEarned = payableAmount
65	                .setScale(0, RoundingMode.FLOOR)
66	                .longValue();
67	
68	        if (pointsEarned <= 0) return;
69	
70	        PointsLedger ledger = PointsLedger.builder()
71	                .memberId(memberId)
72	                .pointsDelta(pointsEarned)
73	                .sourceOrderId(orderId)
74	                .currencyAmountBasis(payableAmount)
75	                .description("Points earned for order " + orderId)
76	                .build();
77	        pointsLedgerRepository.save(ledger);
78	
79	        member.setPointsBalance(member.getPointsBalance() + pointsEarned);
80	        checkAndUpgradeTier(member);   // immediate upgrade (Q5)
81	        memberRepository.save(member);
82	    }
83	
84	    // ------------------------------------------------------------------
85	    // Tier management (Q5)
86	    // ------------------------------------------------------------------
87	
88	    /**
89	     * Upgrade tier immediately whenever the running balance crosses a threshold.
90	     * Only ever promotes – downgrade is handled by the scheduled monthly job.
91	     */
92	    public void checkAndUpgradeTier(Member member) {
93	        MemberTier target = tierForBalance(member.getPointsBalance());
94	        if (target.ordinal() > member.getTier().ordinal()) {
95	            log.info("Upgrading member {} tier: {} → {}", member.getId(), member.getTier(), target);
96	            member.setTier(target);
97	        }
98	        // Intentionally no downgrade here – that is the monthly job's responsibility (Q5)
99	    }
100	
101	    /**
102	     * Monthly scheduled job: recalculate each member's tier from their
103	     * authoritative ledger sum and only LOWER the tier if warranted (Q5).
104	     * Upgrades are already handled immediately at accrual time.
105	     */
106	    @Transactional
107	    public void monthlyTierDowngrade() {
108	        log.info("Running monthly tier downgrade job");
109	        List<Member> allMembers = memberRepository.findAll();
110	        int downgraded = 0;
111	        for (Member member : allMembers) {
112	            // Authoritative balance from ledger (handles any manual adjustments)
113	            Long ledgerTotal = pointsLedgerRepository.sumPointsByMemberId(member.getId());
114	            long authoritative = ledgerTotal != null ? ledgerTotal : 0L;
115	
116	            // Sync the denormalised balance field with the ledger sum
117	            member.setPointsBalance(authoritative);
118	
119	            MemberTier correct = tierForBalance(authoritative);
120	            if (correct.ordinal() < member.getTier().ordinal()) {
121	                // Only downgrade – never promote during this job (Q5)
122	                log.info("Downgrading member {} tier: {} → {}", member.getId(), member.getTier(), correct);
123	                member.setTier(correct);
124	                downgraded++;
125	            }
126	        }
127	        memberRepository.saveAll(allMembers);
128	        log.info("Monthly tier downgrade complete. {} member(s) downgraded.", downgraded);
129	    }
130	
131	    private MemberTier tierForBalance(long balance) {
132	        if (balance >= 5000) return MemberTier.GOLD;
133	        if (balance >= 1000) return MemberTier.SILVER;
134	        return MemberTier.BRONZE;
135	    }
136	
137	    // ------------------------------------------------------------------
138	    // Admin status management (Q3)
139	    // ------------------------------------------------------------------
140	
141	    /**
142	     * Update a member's standing status (ACTIVE / SUSPENDED / DELINQUENT).
143	     * Member pricing is gated on ACTIVE status (Q3), so changing status
144	     * immediately affects pricing eligibility on subsequent orders.
145	     */
146	    @Transactional
147	    public MemberResponse updateStatus(UUID memberId, MemberStatus newStatus, UUID actorId) {
148	        Member member = memberRepository.findById(memberId)
149	                .orElseThrow(() -> new AppException("MEMBER_NOT_FOUND", "Member not found", HttpStatus.NOT_FOUND));
150	
151	        MemberStatus previous = member.getStatus();
152	        member.setStatus(newStatus);
153	
154	        // Record when the member entered good standing
155	        if (newStatus == MemberStatus.ACTIVE && previous != MemberStatus.ACTIVE) {
156	            member.setGoodStandingSince(OffsetDateTime.now());
157	        }
158	
159	        memberRepository.save(member);
160	        log.info("Member {} status changed by actor {}: {} → {}", memberId, actorId, previous, newStatus);
161	        return toResponse(member);
162	    }
163	
164	    /**
165	     * Create a member profile for a new user.
166	     * Called automatically by UserService.createUser so every user starts
167	     * with a BRONZE / ACTIVE membership.
168	     */
169	    @Transactional
170	    public Member createForUser(UUID userId) {
171	        // Idempotent: return existing if already created
172	        Optional<Member> existing = memberRepository.findByUserId(userId);
173	        if (existing.isPresent()) return existing.get();
174	
175	        Member member = Member.builder()
176	                .userId(userId)
177	                .status(MemberStatus.ACTIVE)
178	                .tier(MemberTier.BRONZE)
179	                .pointsBalance(0L)
180	                .goodStandingSince(OffsetDateTime.now())
181	                .build();
182	        return memberRepository.save(member);
183	    }
184	
185	    // ------------------------------------------------------------------
186	    // Mapping helpers
187	    // ------------------------------------------------------------------
188	
189	    public MemberResponse toResponse(Member member) {
190	        return MemberResponse.builder()
191	                .memberId(member.getId())
192	                .userId(member.getUserId())
193	                .status(member.getStatus())
194	                .tier(member.getTier())
195	                .pointsBalance(member.getPointsBalance())
196	                .build();
197	    }
198	
199	    private PointsLedgerResponse toLedgerResponse(PointsLedger p) {
200	        return PointsLedgerResponse.builder()
201	                .id(p.getId())
202	                .pointsDelta(p.getPointsDelta())
203	                .sourceOrderId(p.getSourceOrderId())
204	                .currencyAmountBasis(p.getCurrencyAmountBasis())
205	                .description(p.getDescription())
206	                .createdAt(p.getCreatedAt())
207	                .build();
208	    }
209	
210	    private Member requireByUserId(UUID userId) {
211	        return memberRepository.findByUserId(userId)
212	                .orElseThrow(() -> new AppException(
213	                        "MEMBER_NOT_FOUND", "Member profile not found", HttpStatus.NOT_FOUND));
214	    }
215	}
