2	
3	import com.example.ricms.domain.entity.Role;
4	import com.example.ricms.domain.entity.User;
5	import com.example.ricms.domain.enums.UserStatus;
6	import com.example.ricms.dto.request.CreateUserRequest;
7	import com.example.ricms.dto.response.PageResponse;
8	import com.example.ricms.dto.response.UserResponse;
9	import com.example.ricms.exception.AppException;
10	import com.example.ricms.repository.RoleRepository;
11	import com.example.ricms.repository.UserRepository;
12	import com.example.ricms.security.PermissionEnforcer;
13	import lombok.RequiredArgsConstructor;
14	import org.springframework.data.domain.Page;
15	import org.springframework.data.domain.PageRequest;
16	import org.springframework.http.HttpStatus;
17	import org.springframework.security.crypto.password.PasswordEncoder;
18	import org.springframework.stereotype.Service;
19	import org.springframework.transaction.annotation.Transactional;
20	
21	import java.util.*;
22	import java.util.stream.Collectors;
23	
24	@Service
25	@RequiredArgsConstructor
26	public class UserService {
27	
28	    private final UserRepository userRepository;
29	    private final RoleRepository roleRepository;
30	    private final PasswordEncoder passwordEncoder;
31	    private final PermissionEnforcer permissionEnforcer;
32	    private final AuditService auditService;
33	    private final MemberService memberService;
34	
35	    // ------------------------------------------------------------------
36	    // Reads (USER:READ required)
37	    // ------------------------------------------------------------------
38	
39	    public PageResponse<UserResponse> listUsers(int page, int pageSize, String q) {
40	        permissionEnforcer.require("USER", "READ");
41	        Page<User> users = (q != null && !q.isBlank())
42	                ? userRepository.searchUsers(q, PageRequest.of(page, pageSize))
43	                : userRepository.findAll(PageRequest.of(page, pageSize));
44	        return PageResponse.of(users.map(this::toResponse));
45	    }
46	
47	    public UserResponse getUser(UUID userId) {
48	        permissionEnforcer.require("USER", "READ");
49	        User user = findUser(userId);
50	        return toResponse(user);
51	    }
52	
53	    // ------------------------------------------------------------------
54	    // Writes
55	    // ------------------------------------------------------------------
56	
57	    /**
58	     * Admin-only user creation (USER:WRITE).
59	     * Hashes the password via BCrypt before persistence.
60	     */
61	    @Transactional
62	    public UserResponse createUser(CreateUserRequest request, UUID actorId) {
63	        permissionEnforcer.require("USER", "WRITE");
64	
65	        if (userRepository.findByUsername(request.getUsername()).isPresent()) {
66	            throw new AppException("CONFLICT", "Username already taken: " + request.getUsername(), HttpStatus.CONFLICT);
67	        }
68	
69	        Set<Role> roles = new HashSet<>();
70	        if (request.getRoleIds() != null && !request.getRoleIds().isEmpty()) {
71	            roles = new HashSet<>(roleRepository.findAllById(request.getRoleIds()));
72	        }
73	
74	        User user = User.builder()
75	                .username(request.getUsername())
76	                .passwordHash(passwordEncoder.encode(request.getPassword()))
77	                .status(UserStatus.ACTIVE)
78	                .roles(roles)
79	                .build();
80	        user = userRepository.save(user);
81	
82	        // Automatically provision a BRONZE/ACTIVE member profile for every new user
83	        memberService.createForUser(user.getId());
84	
85	        auditService.record(actorId, "USER", user.getId().toString(),
86	                "CREATE_USER", "ADMIN_ACTION", null,
87	                Map.of("username", user.getUsername(),
88	                       "roles", roles.stream().map(Role::getName).collect(Collectors.toSet())));
89	
90	        return toResponse(user);
91	    }
92	
93	    /**
94	     * Replace a user's full role set (RBAC_USER_ROLES:WRITE).
95	     * The before/after diff records old vs new role names for the audit trail (Q2).
96	     */
97	    @Transactional
98	    public UserResponse assignRoles(UUID userId, List<UUID> roleIds, UUID actorId) {
99	        permissionEnforcer.require("RBAC_USER_ROLES", "WRITE");
100	
101	        User user = findUser(userId);
102	
103	        Set<String> oldRoles = user.getRoles().stream()
104	                .map(Role::getName).collect(Collectors.toSet());
105	
106	        Set<Role> newRoleEntities = new HashSet<>(roleRepository.findAllById(roleIds));
107	        if (newRoleEntities.size() != roleIds.size()) {
108	            throw new AppException("NOT_FOUND", "One or more role IDs not found", HttpStatus.NOT_FOUND);
109	        }
110	        user.setRoles(newRoleEntities);
111	        userRepository.save(user);
112	
113	        Set<String> newRoles = newRoleEntities.stream()
114	                .map(Role::getName).collect(Collectors.toSet());
115	
116	        // Diff: only the 'roles' field changed (Q2)
117	        auditService.record(actorId, "USER", userId.toString(),
118	                "ASSIGN_ROLES", "PERMISSION_CHANGE",
119	                Map.of("roles", oldRoles),
120	                Map.of("roles", newRoles));
121	
122	        return toResponse(user);
123	    }
124	
125	    // ------------------------------------------------------------------
126	
127	    private User findUser(UUID userId) {
128	        return userRepository.findById(userId)
129	                .orElseThrow(() -> new AppException("USER_NOT_FOUND", "User not found", HttpStatus.NOT_FOUND));
130	    }
131	
132	    public UserResponse toResponse(User user) {
133	        return UserResponse.builder()
134	                .id(user.getId())
135	                .username(user.getUsername())
136	                .status(user.getStatus())
137	                .roles(user.getRoles().stream().map(Role::getName).collect(Collectors.toSet()))
138	                .createdAt(user.getCreatedAt())
139	                .build();
140	    }
141	}
