1	package com.example.ricms.service;
2	
3	import com.example.ricms.domain.entity.*;
4	import com.example.ricms.domain.enums.OrderStatus;
5	import com.example.ricms.dto.request.PlaceOrderRequest;
6	import com.example.ricms.dto.response.AttachmentResponse;
7	import com.example.ricms.dto.response.OrderItemResponse;
8	import com.example.ricms.dto.response.OrderResponse;
9	import com.example.ricms.dto.response.PageResponse;
10	import com.example.ricms.dto.response.PricingResult;
11	import com.example.ricms.exception.AppException;
12	import com.example.ricms.repository.*;
13	import com.example.ricms.security.PermissionEnforcer;
14	import lombok.RequiredArgsConstructor;
15	import lombok.extern.slf4j.Slf4j;
16	import org.springframework.data.domain.Page;
17	import org.springframework.data.domain.PageRequest;
18	import org.springframework.http.HttpStatus;
19	import org.springframework.stereotype.Service;
20	import org.springframework.transaction.annotation.Transactional;
21	
22	import java.math.BigDecimal;
23	import java.nio.charset.StandardCharsets;
24	import java.security.MessageDigest;
25	import java.time.OffsetDateTime;
26	import java.util.ArrayList;
27	import java.util.LinkedHashMap;
28	import java.util.List;
29	import java.util.Map;
30	import java.util.Optional;
31	import java.util.UUID;
32	import java.util.concurrent.atomic.AtomicLong;
33	import java.util.stream.Collectors;
34	
35	@Slf4j
36	@Service
37	@RequiredArgsConstructor
38	public class OrderService {
39	
40	    private final OrderRepository orderRepository;
41	    private final OrderItemRepository orderItemRepository;
42	    private final OrderNoteRepository orderNoteRepository;
43	    private final InventoryRepository inventoryRepository;
44	    private final AttachmentRepository attachmentRepository;
45	    private final MemberRepository memberRepository;
46	    private final MemberService memberService;
47	    private final PricingEngine pricingEngine;
48	    private final AuditService auditService;
49	    private final PermissionEnforcer permissionEnforcer;
50	
51	    private static final AtomicLong orderSeq = new AtomicLong(System.currentTimeMillis() % 100000);
52	
53	    @Transactional
54	    public OrderResponse placeOrder(PlaceOrderRequest request, String idempotencyKey) {
55	        permissionEnforcer.require("ORDER", "WRITE");
56	        // Check idempotency
57	        if (idempotencyKey != null && !idempotencyKey.isBlank()) {
58	            String keyHash = hashIdempotencyKey(request.getBuyerId(), idempotencyKey);
59	            Optional<Order> existing = orderRepository.findByBuyerUserIdAndIdempotencyKeyHash(
60	                    request.getBuyerId(), keyHash);
61	            if (existing.isPresent()) {
62	                Order existingOrder = existing.get();
63	                if (existingOrder.getCreatedAt().isAfter(OffsetDateTime.now().minusMinutes(10))) {
64	                    return toResponse(existingOrder);
65	                }
66	            }
67	        }
68	
69	        // Compute subtotal
70	        BigDecimal subtotal = request.getItems().stream()
71	                .map(item -> item.getUnitPrice().multiply(BigDecimal.valueOf(item.getQuantity())))
72	                .reduce(BigDecimal.ZERO, BigDecimal::add);
73	
74	        BigDecimal shippingCost = computeShipping(request.getShippingCountry());
75	
76	        // Pricing
77	        PricingResult pricing = pricingEngine.computePricing(
78	                request.getBuyerId(), subtotal, shippingCost,
79	                request.getCouponCode(), request.getCampaignId());
80	
81	        // All-or-nothing inventory reservation (Q9):
82	        // Pass 1 — acquire pessimistic locks and verify ALL items are available before
83	        //           touching any reserved count. Use a LinkedHashMap to preserve order
84	        //           and deduplicate SKUs (aggregate quantities for duplicate SKU entries).
85	        Map<String, Integer> skuQuantities = new LinkedHashMap<>();
86	        for (var item : request.getItems()) {
87	            skuQuantities.merge(item.getSku(), item.getQuantity(), Integer::sum);
88	        }
89	
90	        Map<String, Inventory> lockedInventory = new LinkedHashMap<>();
91	        for (Map.Entry<String, Integer> entry : skuQuantities.entrySet()) {
92	            String sku = entry.getKey();
93	            int qty     = entry.getValue();
94	            Inventory inv = inventoryRepository.findBySkuWithLock(sku)
95	                    .orElseThrow(() -> new AppException("INVENTORY_NOT_FOUND",
96	                            "SKU not found: " + sku, HttpStatus.NOT_FOUND));
97	            int available = inv.getOnHand() - inv.getReserved();
98	            if (available < qty) {
99	                throw new AppException("INSUFFICIENT_INVENTORY",
100	                        "Insufficient inventory for SKU " + sku +
101	                        ": available=" + available + " requested=" + qty,
102	                        HttpStatus.UNPROCESSABLE_ENTITY);
103	            }
104	            lockedInventory.put(sku, inv);
105	        }
106	
107	        // Pass 2 — all checks passed; reserve every SKU atomically within this TX.
108	        OffsetDateTime reservedUntil = OffsetDateTime.now().plusMinutes(30);
109	        for (Map.Entry<String, Integer> entry : skuQuantities.entrySet()) {
110	            Inventory inv = lockedInventory.get(entry.getKey());
111	            inv.setReserved(inv.getReserved() + entry.getValue());
112	            inv.setReservedUntil(reservedUntil);
113	            inventoryRepository.save(inv);
114	        }
115	
116	        // Create order
117	        String orderNumber = "ORD-" + System.currentTimeMillis() + "-" + orderSeq.incrementAndGet();
118	        String idempotencyKeyHash = idempotencyKey != null ?
119	                hashIdempotencyKey(request.getBuyerId(), idempotencyKey) : null;
120	
121	        Order order = Order.builder()
122	                .orderNumber(orderNumber)
123	                .buyerUserId(request.getBuyerId())
124	                .status(OrderStatus.PLACED)
125	                .subtotal(subtotal)
126	                .discountsTotal(pricing.getDiscountsTotal())
127	                .shippingTotal(pricing.getShippingTotal())
128	                .totalPayable(pricing.getTotalPayable())
129	                .couponId(pricing.getAppliedCouponId())
130	                .campaignId(pricing.getAppliedCampaignId())
131	                .paymentMethod(request.getPaymentMethod())
132	                .shippingCountry(request.getShippingCountry())
133	                .shippingPostalCode(request.getShippingPostalCode())
134	                .idempotencyKeyHash(idempotencyKeyHash)
135	                .items(new ArrayList<>())
136	                .build();
137	
138	        order = orderRepository.save(order);
139	
140	        // Create items
141	        List<OrderItem> items = new ArrayList<>();
142	        for (var itemDto : request.getItems()) {
143	            OrderItem item = OrderItem.builder()
144	                    .orderId(order.getId())
145	                    .sku(itemDto.getSku())
146	                    .quantity(itemDto.getQuantity())
147	                    .unitPrice(itemDto.getUnitPrice())
