209	    @Transactional
210	    public OrderResponse fulfillOrder(UUID orderId) {
211	        permissionEnforcer.require("ORDER", "WRITE");
212	        Order order = orderRepository.findById(orderId)
213	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
214	
215	        if (order.getStatus() != OrderStatus.CONFIRMED_PAYMENT) {
216	            throw new AppException("INVALID_STATE_TRANSITION",
217	                    "Order must be in CONFIRMED_PAYMENT status to fulfill", HttpStatus.CONFLICT);
218	        }
219	
220	        // Q9: All-or-nothing fulfillment — verify that reserved inventory still covers
221	        // ALL items before transitioning. If the reservation window expired and the
222	        // timeout job already released stock for some SKUs, we must not partially fulfill.
223	        List<OrderItem> items = orderItemRepository.findByOrderId(orderId);
224	        Map<String, Integer> skuQuantities = new LinkedHashMap<>();
225	        for (OrderItem item : items) {
226	            skuQuantities.merge(item.getSku(), item.getQuantity(), Integer::sum);
227	        }
228	
229	        List<String> insufficientSkus = new ArrayList<>();
230	        for (Map.Entry<String, Integer> entry : skuQuantities.entrySet()) {
231	            Inventory inv = inventoryRepository.findBySkuWithLock(entry.getKey())
232	                    .orElse(null);
233	            if (inv == null || inv.getReserved() < entry.getValue()) {
234	                insufficientSkus.add(entry.getKey());
235	            }
236	        }
237	        if (!insufficientSkus.isEmpty()) {
238	            throw new AppException("FULFILLMENT_INVENTORY_INSUFFICIENT",
239	                    "Cannot fulfill: insufficient reserved inventory for SKU(s): " +
240	                    String.join(", ", insufficientSkus),
241	                    HttpStatus.UNPROCESSABLE_ENTITY);
242	        }
243	
244	        order.setStatus(OrderStatus.FULFILLMENT_RESERVED);
245	        orderRepository.save(order);
246	        return toResponse(order);
247	    }
