249	    @Transactional
250	    public OrderResponse confirmDelivery(UUID orderId) {
251	        permissionEnforcer.require("ORDER", "WRITE");
252	        Order order = orderRepository.findById(orderId)
253	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
254	
255	        if (order.getStatus() != OrderStatus.FULFILLMENT_RESERVED) {
256	            throw new AppException("INVALID_STATE_TRANSITION",
257	                    "Order must be in FULFILLMENT_RESERVED status", HttpStatus.CONFLICT);
258	        }
259	        order.setStatus(OrderStatus.DELIVERY_CONFIRMED);
260	        orderRepository.save(order);
261	
262	        // Deduct from inventory reservation
263	        List<OrderItem> items = orderItemRepository.findByOrderId(orderId);
264	        for (OrderItem item : items) {
265	            inventoryRepository.findBySkuWithLock(item.getSku()).ifPresent(inv -> {
266	                inv.setReserved(Math.max(0, inv.getReserved() - item.getQuantity()));
267	                inv.setOnHand(Math.max(0, inv.getOnHand() - item.getQuantity()));
268	                inventoryRepository.save(inv);
269	            });
270	        }
271	
272	        return toResponse(order);
273	    }
