326	    @Transactional
327	    public void closeTimedOutOrders() {
328	        OffsetDateTime cutoff = OffsetDateTime.now().minusMinutes(30);
329	        List<Order> timedOut = orderRepository.findTimedOutOrders(cutoff);
330	
331	        for (Order order : timedOut) {
332	            log.info("Closing timed-out order: {}", order.getOrderNumber());
333	            // Release inventory
334	            List<OrderItem> items = orderItemRepository.findByOrderId(order.getId());
335	            for (OrderItem item : items) {
336	                inventoryRepository.findBySkuWithLock(item.getSku()).ifPresent(inv -> {
337	                    inv.setReserved(Math.max(0, inv.getReserved() - item.getQuantity()));
338	                    inventoryRepository.save(inv);
339	                });
340	            }
341	            order.setStatus(OrderStatus.CLOSED);
342	            order.setClosedAt(OffsetDateTime.now());
343	            orderRepository.save(order);
344	        }
345	    }
