354	    private String hashIdempotencyKey(UUID buyerId, String key) {
355	        try {
356	            MessageDigest md = MessageDigest.getInstance("SHA-256");
357	            byte[] hash = md.digest((buyerId.toString() + ":" + key).getBytes(StandardCharsets.UTF_8));
358	            StringBuilder sb = new StringBuilder();
359	            for (byte b : hash) sb.append(String.format("%02x", b));
