210	    private Member requireByUserId(UUID userId) {
211	        return memberRepository.findByUserId(userId)
212	                .orElseThrow(() -> new AppException(
213	                        "MEMBER_NOT_FOUND", "Member profile not found", HttpStatus.NOT_FOUND));
214	    }
215	}
