100	    public WorkOrderResponse addEvent(UUID workOrderId, WorkOrderEventType type, String payload, UUID actorId) {
101	        permissionEnforcer.require("WORK_ORDER", "WRITE");
102	        WorkOrder wo = workOrderRepository.findById(workOrderId)
103	                .orElseThrow(() -> new AppException("WORK_ORDER_NOT_FOUND", "Work order not found", HttpStatus.NOT_FOUND));
