107	        if (type == WorkOrderEventType.FIRST_RESPONSE_SENT && wo.getFirstRespondedAt() == null) {
108	            wo.setFirstRespondedAt(OffsetDateTime.now());
109	        }
110	        if (type == WorkOrderEventType.RESOLUTION_CONFIRMED) {
111	            wo.setResolvedAt(OffsetDateTime.now());
112	            wo.setStatus(WorkOrderStatus.RESOLVED);
113	            // Q12: auto-lock cost on resolution so it can no longer be edited
114	            workOrderCostRepository.findByWorkOrderId(workOrderId).ifPresent(cost -> {
115	                if (cost.getLockedAt() == null) {
116	                    cost.setLockedAt(OffsetDateTime.now());
117	                    cost.setApprovedStatus("APPROVED");
118	                    workOrderCostRepository.save(cost);
119	                }
120	            });
121	        }
122	        if (type == WorkOrderEventType.STATUS_UPDATED) {
123	            // Keep current status unless specified
124	            wo.setStatus(WorkOrderStatus.IN_PROGRESS);
125	        }
126	        workOrderRepository.save(wo);
127	
128	        return toResponse(wo);
129	    }
