350	    /** Minimal SHA-256 hex replication of the service logic for hash matching. */
351	    private String sha256(String input) {
352	        try {
353	            var md = java.security.MessageDigest.getInstance("SHA-256");
354	            byte[] hash = md.digest(input.getBytes(java.nio.charset.StandardCharsets.UTF_8));
355	            var sb = new StringBuilder();
356	            for (byte b : hash) sb.append(String.format("%02x", b));
357	            return sb.toString();
358	        } catch (Exception e) { return input; }
359	    }
