37	    public KpiResponse getKpis() {
38	        permissionEnforcer.require("ADMIN", "READ");
39	        long totalOrders = orderRepository.count();
40	        BigDecimal totalRevenue = orderRepository.sumCompletedRevenue();
41	        long totalMembers = memberRepository.count();
42	        long activeWorkOrders = workOrderRepository.countByStatus(WorkOrderStatus.IN_PROGRESS)
43	                + workOrderRepository.countByStatus(WorkOrderStatus.ASSIGNED)
44	                + workOrderRepository.countByStatus(WorkOrderStatus.SUBMITTED);
45	        long resolvedWorkOrders = workOrderRepository.countByStatus(WorkOrderStatus.RESOLVED)
46	                + workOrderRepository.countByStatus(WorkOrderStatus.CLOSED);
47	        long pendingModerationItems = moderationQueueRepository.countByStatus("PENDING");
48	
49	        return KpiResponse.builder()
50	                .totalOrders(totalOrders)
51	                .totalRevenue(totalRevenue != null ? totalRevenue : BigDecimal.ZERO)
52	                .totalMembers(totalMembers)
53	                .activeWorkOrders(activeWorkOrders)
54	                .resolvedWorkOrders(resolvedWorkOrders)
55	                .pendingModerationItems(pendingModerationItems)
56	                .build();
57	    }
58	
59	    @Transactional
60	    public void setOperationalParam(String key, String valueJson) {
61	        permissionEnforcer.require("ADMIN", "WRITE");
62	        OperationalParam param = operationalParamRepository.findById(key)
63	                .orElseGet(() -> OperationalParam.builder().key(key).build());
64	        param.setValueJson(valueJson);
65	        operationalParamRepository.save(param);
66	    }
67	
68	    public String getOperationalParam(String key) {
69	        permissionEnforcer.require("ADMIN", "READ");
70	        return operationalParamRepository.findById(key)
71	                .map(OperationalParam::getValueJson)
72	                .orElse(null);
73	    }
74	
75	    public byte[] exportOrders(String format) {
76	        permissionEnforcer.require("ADMIN", "READ");
77	        List<Order> orders = orderRepository.findAll();
78	        if ("excel".equalsIgnoreCase(format)) {
79	            return exportOrdersExcel(orders);
80	        } else {
81	            return exportOrdersCsv(orders);
82	        }
83	    }
84	
85	    public byte[] exportWorkOrders(String format) {
86	        permissionEnforcer.require("ADMIN", "READ");
87	        List<WorkOrder> workOrders = workOrderRepository.findAll();
88	        if ("excel".equalsIgnoreCase(format)) {
89	            return exportWorkOrdersExcel(workOrders);
90	        } else {
91	            return exportWorkOrdersCsv(workOrders);
92	        }
93	    }
