95	    private byte[] exportOrdersCsv(List<Order> orders) {
96	        try (StringWriter sw = new StringWriter(); CSVWriter writer = new CSVWriter(sw)) {
97	            writer.writeNext(new String[]{
98	                    "ID", "Order Number", "Buyer ID", "Status",
99	                    "Subtotal", "Discounts", "Shipping", "Total",
100	                    "Payment Method", "Created At"
101	            });
102	            for (Order o : orders) {
103	                writer.writeNext(new String[]{
104	                        o.getId().toString(),
105	                        o.getOrderNumber(),
106	                        o.getBuyerUserId() != null ? o.getBuyerUserId().toString() : "",
107	                        o.getStatus().name(),
108	                        o.getSubtotal().toPlainString(),
109	                        o.getDiscountsTotal().toPlainString(),
110	                        o.getShippingTotal().toPlainString(),
111	                        o.getTotalPayable().toPlainString(),
112	                        o.getPaymentMethod().name(),
113	                        o.getCreatedAt().toString()
114	                });
115	            }
116	            return sw.toString().getBytes(java.nio.charset.StandardCharsets.UTF_8);
117	        } catch (Exception e) {
118	            throw new AppException("EXPORT_FAILED", "Failed to export orders CSV", HttpStatus.INTERNAL_SERVER_ERROR, e);
119	        }
120	    }
121	
122	    private byte[] exportOrdersExcel(List<Order> orders) {
123	        try (Workbook wb = new XSSFWorkbook(); ByteArrayOutputStream out = new ByteArrayOutputStream()) {
124	            Sheet sheet = wb.createSheet("Orders");
125	            String[] headers = {"ID", "Order Number", "Buyer ID", "Status",
126	                    "Subtotal", "Discounts", "Shipping", "Total", "Payment Method", "Created At"};
127	            Row headerRow = sheet.createRow(0);
128	            for (int i = 0; i < headers.length; i++) {
129	                headerRow.createCell(i).setCellValue(headers[i]);
130	            }
131	            int rowNum = 1;
132	            for (Order o : orders) {
133	                Row row = sheet.createRow(rowNum++);
134	                row.createCell(0).setCellValue(o.getId().toString());
135	                row.createCell(1).setCellValue(o.getOrderNumber());
136	                row.createCell(2).setCellValue(o.getBuyerUserId() != null ? o.getBuyerUserId().toString() : "");
137	                row.createCell(3).setCellValue(o.getStatus().name());
138	                row.createCell(4).setCellValue(o.getSubtotal().doubleValue());
139	                row.createCell(5).setCellValue(o.getDiscountsTotal().doubleValue());
140	                row.createCell(6).setCellValue(o.getShippingTotal().doubleValue());
141	                row.createCell(7).setCellValue(o.getTotalPayable().doubleValue());
142	                row.createCell(8).setCellValue(o.getPaymentMethod().name());
143	                row.createCell(9).setCellValue(o.getCreatedAt().toString());
144	            }
145	            wb.write(out);
146	            return out.toByteArray();
147	        } catch (Exception e) {
148	            throw new AppException("EXPORT_FAILED", "Failed to export orders Excel", HttpStatus.INTERNAL_SERVER_ERROR, e);
149	        }
150	    }
