1	package com.example.ricms.controller;
2	
3	import com.example.ricms.dto.request.OperationalParamRequest;
4	import com.example.ricms.dto.response.KpiResponse;
5	import com.example.ricms.exception.AppException;
6	import com.example.ricms.service.AdminService;
7	import jakarta.validation.Valid;
8	import lombok.RequiredArgsConstructor;
9	import org.springframework.http.HttpHeaders;
10	import org.springframework.http.HttpStatus;
11	import org.springframework.http.MediaType;
12	import org.springframework.http.ResponseEntity;
13	import org.springframework.web.bind.annotation.*;
14	
15	@RestController
16	@RequestMapping("/v1/admin")
17	@RequiredArgsConstructor
18	public class AdminController {
19	
20	    private final AdminService adminService;
21	
22	    @GetMapping("/kpis")
23	    public ResponseEntity<KpiResponse> getKpis() {
24	        return ResponseEntity.ok(adminService.getKpis());
25	    }
26	
27	    @PostMapping("/operational-params")
28	    public ResponseEntity<Void> setOperationalParam(@Valid @RequestBody OperationalParamRequest request) {
29	        adminService.setOperationalParam(request.getKey(), request.getValueJson());
30	        return ResponseEntity.noContent().build();
31	    }
32	
33	    @GetMapping("/operational-params/{key}")
34	    public ResponseEntity<String> getOperationalParam(@PathVariable String key) {
35	        String value = adminService.getOperationalParam(key);
36	        if (value == null) {
37	            throw new AppException("PARAM_NOT_FOUND", "Operational parameter not found: " + key, HttpStatus.NOT_FOUND);
38	        }
39	        return ResponseEntity.ok(value);
40	    }
41	
42	    @GetMapping("/exports/{entity}")
43	    public ResponseEntity<byte[]> export(
44	            @PathVariable String entity,
45	            @RequestParam(defaultValue = "csv") String format) {
46	
47	        byte[] data;
48	        String filename;
49	        String contentType = "csv".equalsIgnoreCase(format)
50	                ? "text/csv"
51	                : "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet";
52	        String ext = "csv".equalsIgnoreCase(format) ? ".csv" : ".xlsx";
53	
54	        switch (entity.toLowerCase()) {
55	            case "orders" -> {
56	                data = adminService.exportOrders(format);
57	                filename = "orders" + ext;
58	            }
59	            case "work-orders" -> {
60	                data = adminService.exportWorkOrders(format);
61	                filename = "work_orders" + ext;
62	            }
63	            default -> throw new AppException("UNKNOWN_ENTITY",
64	                    "Unknown export entity: " + entity + ". Supported: orders, work-orders", HttpStatus.BAD_REQUEST);
65	        }
66	
67	        HttpHeaders headers = new HttpHeaders();
68	        headers.set(HttpHeaders.CONTENT_DISPOSITION, "attachment; filename=\"" + filename + "\"");
69	        return ResponseEntity.ok()
70	                .headers(headers)
71	                .contentType(MediaType.parseMediaType(contentType))
72	                .body(data);
73	    }
74	}
