11	import org.springframework.transaction.annotation.Transactional;
12	
13	import java.util.*;
14	
15	/**
16	 * Append-only audit trail (Q1 / Q2).
17	 *
18	 * Diff storage (Q2): rather than persisting full before/after snapshots, we
19	 * compute a field-level diff and store only the changed keys:
20	 *
21	 *   { "roles": {"from": ["MEMBER"], "to": ["MEMBER","ADMIN"]},
22	 *     "status": {"from": "ACTIVE", "to": "SUSPENDED"} }
23	 *
24	 * This keeps each row small and makes the change obvious on inspection.
25	 * The table is append-only (@Immutable entity, no UPDATE issued by the ORM).
26	 *
27	 * Archival (Q2): use Propagation.REQUIRES_NEW so audit writes survive even if
28	 * the outer transaction rolls back. For cold-storage archival, a periodic job
29	 * can move rows older than N months into an audit_events_archive table using
30	 * the existing (resource_type, created_at) index; no code change needed.
31	 */
32	@Slf4j
33	@Service
34	@RequiredArgsConstructor
35	public class AuditService {
36	
37	    private final AuditEventRepository auditEventRepository;
38	    private final ObjectMapper objectMapper;
39	
40	    /**
41	     * Record a privileged action with a diff of changed fields.
42	     *
43	     * @param actorId      user who performed the action (null for system actions)
44	     * @param resourceType domain entity type, e.g. "USER", "ORDER"
45	     * @param subjectId    identifier of the affected resource
46	     * @param operation    verb, e.g. "ASSIGN_ROLES", "PASSWORD_ROTATE"
47	     * @param reasonCode   structured reason, e.g. "ADMIN_ACTION", "USER_REQUEST"
48	     * @param before       previous state (POJO, Map, or null if creating)
49	     * @param after        new state (POJO, Map, or null if deleting)
50	     */
51	    @Transactional(propagation = Propagation.REQUIRES_NEW)
52	    public void record(UUID actorId, String resourceType, String subjectId,
53	                       String operation, String reasonCode, Object before, Object after) {
54	        try {
55	            String diffJson = computeDiff(before, after);
56	            AuditEvent event = AuditEvent.builder()
57	                    .actorUserId(actorId)
58	                    .subjectResourceType(resourceType)
59	                    .subjectId(subjectId)
60	                    .operation(operation)
61	                    .reasonCode(reasonCode)
62	                    .diffPayload(diffJson)
63	                    .build();
64	            auditEventRepository.save(event);
65	        } catch (Exception e) {
66	            // Audit failure must never break the primary transaction
67	            log.error("Failed to record audit event [{}:{}:{}]: {}", resourceType, operation, subjectId, e.getMessage());
68	        }
69	    }
70	
71	    // -------------------------------------------------------------------------
72	    // Diff computation (Q2)
73	    // -------------------------------------------------------------------------
74	
75	    /**
76	     * Compute a field-level diff between two states.
77	     *
78	     * Rules:
79	     * - If both are null → no diff stored (returns null).
80	     * - If before is null → treat as creation, store {"_action":"CREATED","after":{...}}.
81	     * - If after  is null → treat as deletion, store {"_action":"DELETED","before":{...}}.
82	     * - Otherwise → iterate all keys from both maps; emit only keys where
83	     *   the value changed: {"fieldName":{"from":old,"to":new}}.
84	     * - Password / token fields are masked as "[REDACTED]" before serialisation.
85	     */
86	    private String computeDiff(Object before, Object after) throws Exception {
87	        if (before == null && after == null) {
88	            return null;
89	        }
90	
91	        if (before == null) {
92	            Map<String, Object> afterMap = toMap(after);
93	            maskSensitiveFields(afterMap);
94	            return objectMapper.writeValueAsString(
95	                    Map.of("_action", "CREATED", "after", afterMap));
96	        }
97	
98	        if (after == null) {
99	            Map<String, Object> beforeMap = toMap(before);
100	            maskSensitiveFields(beforeMap);
101	            return objectMapper.writeValueAsString(
102	                    Map.of("_action", "DELETED", "before", beforeMap));
103	        }
104	
105	        Map<String, Object> beforeMap = toMap(before);
106	        Map<String, Object> afterMap  = toMap(after);
107	        maskSensitiveFields(beforeMap);
108	        maskSensitiveFields(afterMap);
109	
110	        Map<String, Object> diff = new LinkedHashMap<>();
111	        Set<String> allKeys = new LinkedHashSet<>();
112	        allKeys.addAll(beforeMap.keySet());
113	        allKeys.addAll(afterMap.keySet());
114	
115	        for (String key : allKeys) {
116	            Object bVal = beforeMap.get(key);
117	            Object aVal = afterMap.get(key);
118	            if (!Objects.equals(bVal, aVal)) {
119	                Map<String, Object> change = new LinkedHashMap<>();
120	                change.put("from", bVal != null ? bVal : "<null>");
121	                change.put("to",   aVal != null ? aVal : "<null>");
122	                diff.put(key, change);
123	            }
124	        }
125	
126	        if (diff.isEmpty()) {
127	            return null; // nothing actually changed
128	        }
129	        return objectMapper.writeValueAsString(diff);
130	    }
131	
132	    @SuppressWarnings("unchecked")
133	    private Map<String, Object> toMap(Object obj) {
134	        if (obj instanceof Map) {
135	            return new LinkedHashMap<>((Map<String, Object>) obj);
136	        }
137	        // POJO → Map via Jackson
138	        return objectMapper.convertValue(obj, new TypeReference<Map<String, Object>>() {});
139	    }
140	
141	    private static final Set<String> SENSITIVE_FIELDS = Set.of(
142	            "passwordHash", "password", "token", "accessToken", "secret");
143	
144	    private void maskSensitiveFields(Map<String, Object> map) {
145	        for (String field : SENSITIVE_FIELDS) {
146	            if (map.containsKey(field)) {
147	                map.put(field, "[REDACTED]");
148	            }
149	        }
150	    }
151	}
