3	import com.example.ricms.domain.entity.Coupon;
4	import com.example.ricms.domain.enums.CouponType;
5	import com.example.ricms.dto.request.CouponValidateRequest;
6	import com.example.ricms.dto.response.CouponValidateResponse;
7	import com.example.ricms.repository.CouponRepository;
8	import com.example.ricms.service.PricingEngine;
9	import lombok.RequiredArgsConstructor;
10	import org.springframework.http.ResponseEntity;
11	import org.springframework.web.bind.annotation.*;
12	
13	import java.math.BigDecimal;
14	import java.math.RoundingMode;
15	import java.time.OffsetDateTime;
16	import java.util.Optional;
17	
18	/**
19	 * POST /v1/coupons/validate
20	 *
21	 * Returns the exact discount a specific coupon code would produce for the
22	 * supplied order context, or an explanation of why it is not applicable.
23	 * This is a read-only preview; it does not reserve or consume the coupon.
24	 */
25	@RestController
26	@RequestMapping("/v1/coupons")
27	@RequiredArgsConstructor
28	public class CouponController {
29	
30	    private final CouponRepository couponRepository;
31	    private final PricingEngine pricingEngine;
32	
33	    @PostMapping("/validate")
34	    public ResponseEntity<CouponValidateResponse> validate(
35	            @RequestBody CouponValidateRequest request) {
36	
37	        String code     = request.getCouponCode();
38	        BigDecimal sub  = contextSubtotal(request);
39	        OffsetDateTime now = OffsetDateTime.now();
40	
41	        if (code == null || code.isBlank()) {
42	            return ResponseEntity.ok(reject(null, "Coupon code is required"));
43	        }
44	
45	        Optional<Coupon> opt = couponRepository.findByCode(code.toUpperCase().trim());
46	        if (opt.isEmpty()) {
47	            return ResponseEntity.ok(reject(code, "Coupon code not found"));
48	        }
49	
50	        Coupon c = opt.get();
51	        if (!c.isActive()) {
52	            return ResponseEntity.ok(reject(code, "Coupon is inactive"));
53	        }
54	        if (c.getActiveFrom() != null && c.getActiveFrom().isAfter(now)) {
55	            return ResponseEntity.ok(reject(code, "Coupon has not started yet"));
56	        }
57	        if (c.getActiveTo() != null && c.getActiveTo().isBefore(now)) {
58	            return ResponseEntity.ok(reject(code, "Coupon has expired"));
59	        }
60	
61	        // Compute discount for this specific coupon type
62	        return switch (c.getType()) {
63	            case THRESHOLD_DISCOUNT -> {
64	                BigDecimal threshold = orZero(c.getThresholdAmount());
65	                if (sub.compareTo(threshold) < 0) {
66	                    yield ResponseEntity.ok(reject(code,
67	                            "Order subtotal $" + sub.toPlainString() +
68	                            " below threshold $" + threshold.toPlainString()));
69	                }
70	                yield ResponseEntity.ok(accept(c, orZero(c.getDiscountAmount()), false));
71	            }
72	            case PERCENTAGE_DISCOUNT -> {
73	                BigDecimal pct      = orZero(c.getDiscountPercent());
74	                BigDecimal computed = sub.multiply(pct)
75	                        .divide(BigDecimal.valueOf(100), 2, RoundingMode.HALF_UP);
76	                if (c.getMaxDiscountAmount() != null && computed.compareTo(c.getMaxDiscountAmount()) > 0) {
77	                    computed = c.getMaxDiscountAmount();
78	                }
79	                yield ResponseEntity.ok(accept(c, computed, false));
80	            }
81	            case SHIPPING_WAIVER -> {
82	                BigDecimal threshold = orZero(c.getThresholdAmount());
83	                if (threshold.compareTo(BigDecimal.ZERO) > 0 && sub.compareTo(threshold) < 0) {
84	                    yield ResponseEntity.ok(reject(code,
85	                            "Order subtotal below shipping waiver threshold $" + threshold.toPlainString()));
86	                }
87	                yield ResponseEntity.ok(accept(c, BigDecimal.ZERO, true));
88	            }
89	        };
90	    }
91	
92	    // ------------------------------------------------------------------
93	
94	    private BigDecimal contextSubtotal(CouponValidateRequest req) {
95	        if (req.getOrderContext() != null && req.getOrderContext().getSubtotal() != null)
96	            return req.getOrderContext().getSubtotal();
97	        return BigDecimal.ZERO;
98	    }
99	
100	    private BigDecimal orZero(BigDecimal v) {
101	        return v != null ? v : BigDecimal.ZERO;
102	    }
103	
104	    private CouponValidateResponse accept(Coupon c, BigDecimal amount, boolean waivedShipping) {
105	        return CouponValidateResponse.builder()
106	                .isValid(true)
107	                .couponId(c.getId())
108	                .couponCode(c.getCode())
109	                .couponType(c.getType().name())
110	                .discountAmount(amount)
111	                .currency("USD")
112	                .waivedShipping(waivedShipping)
113	                .build();
114	    }
115	
116	    private CouponValidateResponse reject(String code, String reason) {
117	        return CouponValidateResponse.builder()
118	                .isValid(false)
119	                .couponCode(code)
120	                .discountAmount(BigDecimal.ZERO)
121	                .currency("USD")
122	                .reason(reason)
123	                .build();
124	    }
125	}
