4	import com.example.ricms.dto.request.CampaignValidateRequest;
5	import com.example.ricms.dto.response.CampaignValidateResponse;
6	import com.example.ricms.repository.CampaignRepository;
7	import com.example.ricms.service.PricingEngine;
8	import com.fasterxml.jackson.databind.JsonNode;
9	import com.fasterxml.jackson.databind.ObjectMapper;
10	import lombok.RequiredArgsConstructor;
11	import lombok.extern.slf4j.Slf4j;
12	import org.springframework.http.ResponseEntity;
13	import org.springframework.web.bind.annotation.*;
14	
15	import java.math.BigDecimal;
16	import java.math.RoundingMode;
17	import java.time.OffsetDateTime;
18	import java.util.Optional;
19	import java.util.UUID;
20	
21	/**
22	 * POST /v1/campaigns/validate
23	 *
24	 * Returns the discount a specific campaign would produce for the supplied
25	 * order context. Does not mutate state.
26	 */
27	@Slf4j
28	@RestController
29	@RequestMapping("/v1/campaigns")
30	@RequiredArgsConstructor
31	public class CampaignController {
32	
33	    private final CampaignRepository campaignRepository;
34	    private final PricingEngine pricingEngine;
35	    private final ObjectMapper objectMapper;
36	
37	    @PostMapping("/validate")
38	    public ResponseEntity<CampaignValidateResponse> validate(
39	            @RequestBody CampaignValidateRequest request) {
40	
41	        UUID campaignId = request.getCampaignId();
42	        BigDecimal sub  = contextSubtotal(request);
43	        OffsetDateTime now = OffsetDateTime.now();
44	
45	        if (campaignId == null) {
46	            return ResponseEntity.ok(reject(null, "Campaign ID is required"));
47	        }
48	
49	        Optional<Campaign> opt = campaignRepository.findById(campaignId);
50	        if (opt.isEmpty()) {
51	            return ResponseEntity.ok(reject(campaignId, "Campaign not found"));
52	        }
53	
54	        Campaign c = opt.get();
55	        if (!c.isActive()) {
56	            return ResponseEntity.ok(reject(campaignId, "Campaign is inactive"));
57	        }
58	        if (c.getActiveFrom() != null && c.getActiveFrom().isAfter(now)) {
59	            return ResponseEntity.ok(reject(campaignId, "Campaign has not started yet"));
60	        }
61	        if (c.getActiveTo() != null && c.getActiveTo().isBefore(now)) {
62	            return ResponseEntity.ok(reject(campaignId, "Campaign has expired"));
63	        }
64	
65	        BigDecimal discount = computeDiscount(c, sub);
66	        if (discount.compareTo(BigDecimal.ZERO) <= 0) {
67	            return ResponseEntity.ok(reject(campaignId,
68	                    "Order does not meet the campaign's eligibility conditions"));
69	        }
70	
71	        return ResponseEntity.ok(CampaignValidateResponse.builder()
72	                .isValid(true)
73	                .campaignId(c.getId())
74	                .campaignName(c.getName())
75	                .campaignType(c.getType().name())
76	                .discountAmount(discount)
77	                .currency("USD")
78	                .build());
79	    }
80	
81	    // ------------------------------------------------------------------
82	
83	    private BigDecimal computeDiscount(Campaign c, BigDecimal subtotal) {
84	        try {
85	            if (c.getParams() == null) return BigDecimal.ZERO;
86	            JsonNode params = objectMapper.readTree(c.getParams());
87	
88	            return switch (c.getType()) {
89	                case SPEND_AND_GET -> {
90	                    BigDecimal threshold = decimal(params, "spendThreshold");
91	                    yield subtotal.compareTo(threshold) >= 0
92	                            ? decimal(params, "rewardAmount")
93	                            : BigDecimal.ZERO;
94	                }
95	                case SECOND_ITEM_DISCOUNT -> {
96	                    BigDecimal pct     = decimal(params, "discountPercent");
97	                    BigDecimal halfSub = subtotal.divide(BigDecimal.valueOf(2), 2, RoundingMode.HALF_UP);
98	                    yield halfSub.multiply(pct).divide(BigDecimal.valueOf(100), 2, RoundingMode.HALF_UP);
99	                }
100	            };
101	        } catch (Exception e) {
102	            log.warn("Campaign discount computation failed: {}", e.getMessage());
103	            return BigDecimal.ZERO;
104	        }
105	    }
106	
107	    private BigDecimal decimal(JsonNode node, String field) {
108	        JsonNode n = node.get(field);
109	        return (n != null && !n.isNull())
110	                ? BigDecimal.valueOf(n.asDouble()).setScale(2, RoundingMode.HALF_UP)
111	                : BigDecimal.ZERO;
112	    }
113	
114	    private BigDecimal contextSubtotal(CampaignValidateRequest req) {
115	        if (req.getOrderContext() != null && req.getOrderContext().getSubtotal() != null)
116	            return req.getOrderContext().getSubtotal();
117	        return BigDecimal.ZERO;
118	    }
119	
120	    private CampaignValidateResponse reject(UUID campaignId, String reason) {
121	        return CampaignValidateResponse.builder()
122	                .isValid(false)
123	                .campaignId(campaignId)
124	                .discountAmount(BigDecimal.ZERO)
125	                .currency("USD")
126	                .reason(reason)
127	                .build();
128	    }
129	}
