7	import com.example.ricms.domain.enums.CouponType;
8	import com.example.ricms.domain.enums.MemberStatus;
9	import com.example.ricms.dto.response.PricingResult;
10	import com.example.ricms.repository.CampaignRepository;
11	import com.example.ricms.repository.CouponRepository;
12	import com.example.ricms.repository.MemberRepository;
13	import com.fasterxml.jackson.databind.JsonNode;
14	import com.fasterxml.jackson.databind.ObjectMapper;
15	import lombok.RequiredArgsConstructor;
16	import lombok.extern.slf4j.Slf4j;
17	import org.springframework.stereotype.Service;
18	
19	import java.math.BigDecimal;
20	import java.math.RoundingMode;
21	import java.time.OffsetDateTime;
22	import java.util.List;
23	import java.util.Optional;
24	import java.util.UUID;
