26	/**
27	 * Deterministic pricing engine (Q3 / Q4 / Q6).
28	 *
29	 * Priority chain (Q6):
30	 *   1. Member price  – only if member status == ACTIVE (Q3)
31	 *   2. Fixed-amount (threshold) coupon
32	 *   3. Percentage coupon  (capped at maxDiscountAmount)
33	 *   4. Shipping-waiver coupon
34	 *
35	 * Stacking (Q6):
36	 *   – At most ONE coupon (client-supplied code).
37	 *   – At most ONE campaign (client-supplied ID, or auto-selected highest-priority eligible).
38	 *   – Coupon discount and campaign discount are cumulative; they are not in competition.
39	 *     The priority chain only governs which coupon TYPE is used when the client provides
40	 *     a code whose type conflicts with another eligible type – in practice the client
41	 *     names exactly one code, so the chain resolves ambiguity in auto-selection flows.
42	 *
43	 * Points basis (Q4):
44	 *   totalPayable returned here is the value used by OrderService to accrue points.
45	 */
46	@Slf4j
47	@Service
48	@RequiredArgsConstructor
49	public class PricingEngine {
50	
51	    private final CouponRepository couponRepository;
52	    private final CampaignRepository campaignRepository;
53	    private final MemberRepository memberRepository;
54	    private final ObjectMapper objectMapper;
55	
56	    // ------------------------------------------------------------------
57	    // Public API
58	    // ------------------------------------------------------------------
59	
60	    /**
61	     * Compute the full pricing breakdown for an order.
62	     *
63	     * @param buyerId      the purchasing user's ID (may be null for anonymous)
64	     * @param subtotal     pre-discount item subtotal
65	     * @param shippingCost raw shipping cost before any waiver
66	     * @param couponCode   optional coupon code supplied by the buyer
67	     * @param campaignId   optional campaign ID supplied by the buyer;
68	     *                     if null the engine auto-selects the best eligible campaign
69	     */
70	    public PricingResult computePricing(UUID buyerId,
71	                                        BigDecimal subtotal,
72	                                        BigDecimal shippingCost,
73	                                        String couponCode,
74	                                        UUID campaignId) {
75	
76	        BigDecimal sub        = nullSafe(subtotal);
77	        BigDecimal ship       = nullSafe(shippingCost);
78	        OffsetDateTime now    = OffsetDateTime.now();
79	
80	        // ── Step 1: Member status gate (Q3) ──────────────────────────────
81	        boolean memberActive = isMemberActive(buyerId);
82	
83	        // ── Step 2: Resolve coupon ────────────────────────────────────────
84	        CouponApplication coupon = resolveCoupon(couponCode, sub, ship, memberActive, now);
85	
86	        // ── Step 3: Resolve campaign ──────────────────────────────────────
87	        //   If the buyer specified a campaign ID, use that.
88	        //   Otherwise auto-select the highest-priority eligible campaign (Q6).
89	        CampaignApplication campaign = resolveCampaign(campaignId, sub, memberActive, now);
90	
91	        // ── Step 4: Compute totals ────────────────────────────────────────
92	        BigDecimal couponDiscount   = coupon.discount;
93	        BigDecimal campaignDiscount = campaign.discount;
94	        BigDecimal totalDiscount    = couponDiscount.add(campaignDiscount);
95	
96	        // Discounts must not exceed the item subtotal
97	        if (totalDiscount.compareTo(sub) > 0) {
98	            totalDiscount = sub;
99	        }
100	
101	        BigDecimal finalSubtotal = sub.subtract(totalDiscount).max(BigDecimal.ZERO);
102	        BigDecimal finalShipping = coupon.waivedShipping ? BigDecimal.ZERO : ship;
103	        BigDecimal totalPayable  = finalSubtotal.add(finalShipping);
104	
105	        return PricingResult.builder()
106	                .memberPricingEligible(memberActive)
107	                .finalSubtotal(finalSubtotal)
108	                .discountsTotal(totalDiscount)
109	                .shippingTotal(finalShipping)
110	                .totalPayable(totalPayable)
111	                .appliedCouponId(coupon.id)
112	                .appliedCouponCode(coupon.code)
113	                .appliedCampaignId(campaign.id)
114	                .appliedCampaignName(campaign.name)
115	                .build();
116	    }
117	
118	    // ------------------------------------------------------------------
119	    // Member status check (Q3)
120	    // ------------------------------------------------------------------
121	
122	    private boolean isMemberActive(UUID buyerId) {
123	        if (buyerId == null) return false;
124	        return memberRepository.findByUserId(buyerId)
125	                .map(m -> m.getStatus() == MemberStatus.ACTIVE)
126	                .orElse(false);
127	    }
128	
129	    // ------------------------------------------------------------------
130	    // Coupon resolution  (Q6 priority chain)
131	    // ------------------------------------------------------------------
132	
133	    /**
134	     * Validate and apply a single, explicitly provided coupon code.
135	     *
136	     * If the coupon exists and is active, compute its discount; otherwise
137	     * the result has zero discount and a reason explaining why it was rejected.
138	     *
139	     * Priority chain (governs auto-selection if ever extended; here the client
140	     * names one code so we validate and apply it directly):
141	     *   THRESHOLD_DISCOUNT > PERCENTAGE_DISCOUNT > SHIPPING_WAIVER
142	     *
143	     * Member pricing gate: if the coupon is tagged member-only (future flag),
144	     * memberActive must be true. For now all coupons are universally available;
145	     * the memberActive flag is passed through for forward-compatibility.
146	     */
147	    private CouponApplication resolveCoupon(String couponCode,
148	                                             BigDecimal subtotal,
149	                                             BigDecimal shippingCost,
150	                                             boolean memberActive,
151	                                             OffsetDateTime now) {
152	        if (couponCode == null || couponCode.isBlank()) {
153	            return CouponApplication.none();
154	        }
155	
156	        Optional<Coupon> opt = couponRepository.findByCode(couponCode.toUpperCase().trim());
157	        if (opt.isEmpty()) {
158	            return CouponApplication.rejected("Coupon not found");
159	        }
160	
161	        Coupon c = opt.get();
162	        if (!c.isActive()) {
163	            return CouponApplication.rejected("Coupon is inactive");
164	        }
165	        if (c.getActiveFrom() != null && c.getActiveFrom().isAfter(now)) {
166	            return CouponApplication.rejected("Coupon has not started yet");
167	        }
168	        if (c.getActiveTo() != null && c.getActiveTo().isBefore(now)) {
169	            return CouponApplication.rejected("Coupon has expired");
170	        }
171	
172	        return switch (c.getType()) {
173	            case THRESHOLD_DISCOUNT -> applyThreshold(c, subtotal);
174	            case PERCENTAGE_DISCOUNT -> applyPercentage(c, subtotal);
175	            case SHIPPING_WAIVER -> applyShippingWaiver(c, subtotal);
176	        };
177	    }
178	
179	    /** $X off orders ≥ threshold. */
180	    private CouponApplication applyThreshold(Coupon c, BigDecimal subtotal) {
181	        BigDecimal threshold = nullSafe(c.getThresholdAmount());
182	        if (subtotal.compareTo(threshold) < 0) {
183	            return CouponApplication.rejected(
184	                    "Order subtotal $" + subtotal.toPlainString() +
185	                    " below required threshold $" + threshold.toPlainString());
186	        }
187	        BigDecimal discount = nullSafe(c.getDiscountAmount());
188	        return CouponApplication.of(c.getId(), c.getCode(), discount, false);
189	    }
190	
191	    /** X% off, capped at maxDiscountAmount. */
192	    private CouponApplication applyPercentage(Coupon c, BigDecimal subtotal) {
193	        BigDecimal pct      = nullSafe(c.getDiscountPercent());
194	        BigDecimal computed = subtotal.multiply(pct)
195	                .divide(BigDecimal.valueOf(100), 2, RoundingMode.HALF_UP);
196	        if (c.getMaxDiscountAmount() != null && computed.compareTo(c.getMaxDiscountAmount()) > 0) {
197	            computed = c.getMaxDiscountAmount();
198	        }
199	        return CouponApplication.of(c.getId(), c.getCode(), computed, false);
200	    }
201	
202	    /** Zero shipping if subtotal ≥ threshold. */
203	    private CouponApplication applyShippingWaiver(Coupon c, BigDecimal subtotal) {
204	        BigDecimal threshold = nullSafe(c.getThresholdAmount());
205	        if (threshold.compareTo(BigDecimal.ZERO) > 0 && subtotal.compareTo(threshold) < 0) {
206	            return CouponApplication.rejected(
207	                    "Order subtotal below shipping waiver threshold $" + threshold.toPlainString());
208	        }
209	        return CouponApplication.of(c.getId(), c.getCode(), BigDecimal.ZERO, true);
210	    }
211	
212	    // ------------------------------------------------------------------
213	    // Campaign resolution (Q6)
214	    // ------------------------------------------------------------------
215	
216	    /**
217	     * Select and compute the campaign discount.
218	     *
219	     * If campaignId is provided: validate and apply that campaign.
220	     * If null: scan all currently active campaigns, compute each eligible
221	     * discount, and pick the one with the highest {@code priority} value (Q6).
222	     */
223	    private CampaignApplication resolveCampaign(UUID campaignId,
224	                                                  BigDecimal subtotal,
225	                                                  boolean memberActive,
226	                                                  OffsetDateTime now) {
227	        if (campaignId != null) {
228	            return campaignRepository.findById(campaignId)
229	                    .map(c -> evaluateCampaign(c, subtotal, memberActive, now))
230	                    .orElse(CampaignApplication.none());
231	        }
232	
233	        // Auto-select: highest-priority eligible campaign (Q6)
234	        List<Campaign> active = campaignRepository.findActiveCampaignsByNow(now);
235	        // list is already ordered by priority DESC from the repository query
236	        for (Campaign c : active) {
237	            CampaignApplication result = evaluateCampaign(c, subtotal, memberActive, now);
238	            if (result.id != null) {
239	                return result;   // first eligible is highest priority
240	            }
241	        }
242	        return CampaignApplication.none();
243	    }
244	
245	    private CampaignApplication evaluateCampaign(Campaign c, BigDecimal subtotal,
246	                                                   boolean memberActive,
247	                                                   OffsetDateTime now) {
248	        if (!c.isActive()) return CampaignApplication.none();
249	        if (c.getActiveFrom() != null && c.getActiveFrom().isAfter(now)) return CampaignApplication.none();
250	        if (c.getActiveTo()   != null && c.getActiveTo().isBefore(now))  return CampaignApplication.none();
251	
252	        BigDecimal discount = computeCampaignDiscount(c, subtotal);
253	        if (discount.compareTo(BigDecimal.ZERO) <= 0) return CampaignApplication.none();
254	        return CampaignApplication.of(c.getId(), c.getName(), discount);
255	    }
256	
257	    /**
258	     * Compute the monetary discount amount for a campaign given the order subtotal.
259	     *
260	     * SPEND_AND_GET: flat reward if subtotal ≥ spendThreshold.
261	     * SECOND_ITEM_DISCOUNT: discountPercent% off half the subtotal
262	     *   (approximation: assumes items of equal value; real implementation
263	     *    needs item-level data passed from OrderService).
264	     */
265	    private BigDecimal computeCampaignDiscount(Campaign campaign, BigDecimal subtotal) {
266	        try {
267	            String paramsJson = campaign.getParams();
268	            if (paramsJson == null || paramsJson.isBlank()) return BigDecimal.ZERO;
269	            JsonNode params = objectMapper.readTree(paramsJson);
270	
271	            return switch (campaign.getType()) {
272	                case SPEND_AND_GET -> {
273	                    BigDecimal threshold = decimal(params, "spendThreshold");
274	                    if (subtotal.compareTo(threshold) >= 0) {
275	                        yield decimal(params, "rewardAmount");
276	                    }
277	                    yield BigDecimal.ZERO;
278	                }
279	                case SECOND_ITEM_DISCOUNT -> {
280	                    // Apply discountPercent% off half the subtotal
281	                    // (represents one second item at X% off when all items are equal price).
282	                    BigDecimal pct        = decimal(params, "discountPercent");
283	                    BigDecimal halfSub    = subtotal.divide(BigDecimal.valueOf(2), 2, RoundingMode.HALF_UP);
284	                    yield halfSub.multiply(pct).divide(BigDecimal.valueOf(100), 2, RoundingMode.HALF_UP);
285	                }
286	            };
287	        } catch (Exception e) {
288	            log.warn("Could not compute campaign discount for campaign {}: {}", campaign.getId(), e.getMessage());
289	            return BigDecimal.ZERO;
290	        }
291	    }
292	
293	    // ------------------------------------------------------------------
294	    // Helpers
295	    // ------------------------------------------------------------------
296	
297	    private BigDecimal decimal(JsonNode node, String field) {
298	        JsonNode n = node.get(field);
299	        if (n == null || n.isNull()) return BigDecimal.ZERO;
300	        return BigDecimal.valueOf(n.asDouble()).setScale(2, RoundingMode.HALF_UP);
301	    }
302	
303	    private static BigDecimal nullSafe(BigDecimal v) {
304	        return v != null ? v : BigDecimal.ZERO;
305	    }
306	
307	    // ------------------------------------------------------------------
308	    // Value objects (package-private for testability)
309	    // ------------------------------------------------------------------
310	
311	    static class CouponApplication {
312	        final UUID       id;
313	        final String     code;
314	        final BigDecimal discount;
315	        final boolean    waivedShipping;
316	        final String     rejectionReason;
317	
318	        private CouponApplication(UUID id, String code, BigDecimal discount,
319	                                   boolean waivedShipping, String rejectionReason) {
320	            this.id              = id;
321	            this.code            = code;
322	            this.discount        = discount;
323	            this.waivedShipping  = waivedShipping;
324	            this.rejectionReason = rejectionReason;
325	        }
326	
327	        static CouponApplication none() {
328	            return new CouponApplication(null, null, BigDecimal.ZERO, false, null);
329	        }
330	        static CouponApplication rejected(String reason) {
331	            return new CouponApplication(null, null, BigDecimal.ZERO, false, reason);
332	        }
333	        static CouponApplication of(UUID id, String code, BigDecimal discount, boolean waiveShipping) {
334	            return new CouponApplication(id, code, discount, waiveShipping, null);
335	        }
336	        boolean isValid() { return id != null; }
337	    }
338	
339	    static class CampaignApplication {
340	        final UUID       id;
341	        final String     name;
342	        final BigDecimal discount;
343	
344	        private CampaignApplication(UUID id, String name, BigDecimal discount) {
345	            this.id       = id;
346	            this.name     = name;
347	            this.discount = discount;
348	        }
349	
350	        static CampaignApplication none() {
351	            return new CampaignApplication(null, null, BigDecimal.ZERO);
352	        }
353	        static CampaignApplication of(UUID id, String name, BigDecimal discount) {
354	            return new CampaignApplication(id, name, discount);
355	        }
356	    }
357	}
