12	@Data
13	@Builder
14	@NoArgsConstructor
15	@AllArgsConstructor
16	@EqualsAndHashCode(of = "id")
17	public class ModerationQueue {
18	
19	    @Id
20	    @GeneratedValue(strategy = GenerationType.AUTO)
21	    @Column(columnDefinition = "uuid DEFAULT gen_random_uuid()")
22	    private UUID id;
23	
24	    @Column(name = "queue_type", nullable = false, length = 50)
