217	    @Transactional
218	    public OrderResponse fulfillOrder(UUID orderId) {
219	        permissionEnforcer.require("ORDER", "WRITE");
220	        Order order = orderRepository.findById(orderId)
221	                .orElseThrow(() -> new AppException("ORDER_NOT_FOUND", "Order not found", HttpStatus.NOT_FOUND));
222	
223	        if (order.getStatus() != OrderStatus.CONFIRMED_PAYMENT) {
224	            throw new AppException("INVALID_STATE_TRANSITION",
225	                    "Order must be in CONFIRMED_PAYMENT status to fulfill", HttpStatus.CONFLICT);
226	        }
227	
228	        // Q9: All-or-nothing fulfillment — verify that reserved inventory still covers
229	        // ALL items before transitioning. If the reservation window expired and the
230	        // timeout job already released stock for some SKUs, we must not partially fulfill.
231	        List<OrderItem> items = orderItemRepository.findByOrderId(orderId);
232	        Map<String, Integer> skuQuantities = new LinkedHashMap<>();
233	        for (OrderItem item : items) {
234	            skuQuantities.merge(item.getSku(), item.getQuantity(), Integer::sum);
235	        }
236	
237	        List<String> insufficientSkus = new ArrayList<>();
238	        for (Map.Entry<String, Integer> entry : skuQuantities.entrySet()) {
239	            Inventory inv = inventoryRepository.findBySkuWithLock(entry.getKey())
240	                    .orElse(null);
241	            if (inv == null || inv.getReserved() < entry.getValue()) {
242	                insufficientSkus.add(entry.getKey());
243	            }
244	        }
245	        if (!insufficientSkus.isEmpty()) {
246	            throw new AppException("FULFILLMENT_INVENTORY_INSUFFICIENT",
247	                    "Cannot fulfill: insufficient reserved inventory for SKU(s): " +
248	                    String.join(", ", insufficientSkus),
249	                    HttpStatus.UNPROCESSABLE_ENTITY);
250	        }
251	
252	        order.setStatus(OrderStatus.FULFILLMENT_RESERVED);
253	        orderRepository.save(order);
254	        return toResponse(order);
255	    }
