334	    @Transactional
335	    public void closeTimedOutOrders() {
336	        OffsetDateTime cutoff = OffsetDateTime.now().minusMinutes(30);
337	        List<Order> timedOut = orderRepository.findTimedOutOrders(cutoff);
338	
339	        for (Order order : timedOut) {
340	            log.info("Closing timed-out order: {}", order.getOrderNumber());
341	            // Release inventory
342	            List<OrderItem> items = orderItemRepository.findByOrderId(order.getId());
343	            for (OrderItem item : items) {
344	                inventoryRepository.findBySkuWithLock(item.getSku()).ifPresent(inv -> {
345	                    inv.setReserved(Math.max(0, inv.getReserved() - item.getQuantity()));
346	                    inventoryRepository.save(inv);
347	                });
348	            }
349	            order.setStatus(OrderStatus.CLOSED);
350	            order.setClosedAt(OffsetDateTime.now());
351	            orderRepository.save(order);
352	            auditService.record(null, "INVENTORY", order.getOrderNumber(),
353	                    "INVENTORY_RELEASE", "SYSTEM_TIMEOUT",
354	                    null, Map.of("orderId", order.getId().toString()));
355	        }
356	    }
