365	    private String hashIdempotencyKey(UUID buyerId, String key) {
366	        try {
367	            MessageDigest md = MessageDigest.getInstance("SHA-256");
368	            byte[] hash = md.digest((buyerId.toString() + ":" + key).getBytes(StandardCharsets.UTF_8));
369	            StringBuilder sb = new StringBuilder();
370	            for (byte b : hash) sb.append(String.format("%02x", b));
371	            return sb.toString();
372	        } catch (Exception e) {
373	            return key;
374	        }
375	    }
