54	    @Transactional
55	    public OrderResponse placeOrder(PlaceOrderRequest request, String idempotencyKey) {
56	        permissionEnforcer.require("ORDER", "WRITE");
57	        // Check idempotency
58	        if (idempotencyKey != null && !idempotencyKey.isBlank()) {
59	            String keyHash = hashIdempotencyKey(request.getBuyerId(), idempotencyKey);
60	            Optional<Order> existing = orderRepository.findByBuyerUserIdAndIdempotencyKeyHash(
61	                    request.getBuyerId(), keyHash);
62	            if (existing.isPresent()) {
63	                Order existingOrder = existing.get();
64	                if (existingOrder.getCreatedAt().isAfter(OffsetDateTime.now().minusMinutes(10))) {
65	                    return toResponse(existingOrder);
66	                }
67	            }
68	        }
69	
70	        // Compute subtotal
71	        BigDecimal subtotal = request.getItems().stream()
72	                .map(item -> item.getUnitPrice().multiply(BigDecimal.valueOf(item.getQuantity())))
73	                .reduce(BigDecimal.ZERO, BigDecimal::add);
74	
75	        BigDecimal shippingCost = computeShipping(request.getShippingCountry());
76	
77	        // Pricing
78	        PricingResult pricing = pricingEngine.computePricing(
79	                request.getBuyerId(), subtotal, shippingCost,
80	                request.getCouponCode(), request.getCampaignId());
81	
82	        // All-or-nothing inventory reservation (Q9):
83	        // Pass 1 — acquire pessimistic locks and verify ALL items are available before
84	        //           touching any reserved count. Use a LinkedHashMap to preserve order
85	        //           and deduplicate SKUs (aggregate quantities for duplicate SKU entries).
86	        Map<String, Integer> skuQuantities = new LinkedHashMap<>();
87	        for (var item : request.getItems()) {
88	            skuQuantities.merge(item.getSku(), item.getQuantity(), Integer::sum);
89	        }
90	
91	        Map<String, Inventory> lockedInventory = new LinkedHashMap<>();
92	        for (Map.Entry<String, Integer> entry : skuQuantities.entrySet()) {
93	            String sku = entry.getKey();
94	            int qty     = entry.getValue();
95	            Inventory inv = inventoryRepository.findBySkuWithLock(sku)
96	                    .orElseThrow(() -> new AppException("INVENTORY_NOT_FOUND",
97	                            "SKU not found: " + sku, HttpStatus.NOT_FOUND));
98	            int available = inv.getOnHand() - inv.getReserved();
99	            if (available < qty) {
100	                throw new AppException("INSUFFICIENT_INVENTORY",
101	                        "Insufficient inventory for SKU " + sku +
102	                        ": available=" + available + " requested=" + qty,
103	                        HttpStatus.UNPROCESSABLE_ENTITY);
104	            }
105	            lockedInventory.put(sku, inv);
106	        }
107	
108	        // Pass 2 — all checks passed; reserve every SKU atomically within this TX.
109	        OffsetDateTime reservedUntil = OffsetDateTime.now().plusMinutes(30);
110	        for (Map.Entry<String, Integer> entry : skuQuantities.entrySet()) {
111	            Inventory inv = lockedInventory.get(entry.getKey());
112	            inv.setReserved(inv.getReserved() + entry.getValue());
113	            inv.setReservedUntil(reservedUntil);
114	            inventoryRepository.save(inv);
115	        }
116	        auditService.record(request.getBuyerId(), "INVENTORY", null,
117	                "INVENTORY_RESERVE", "USER_ACTION",
118	                null, Map.of("skus", skuQuantities));
119	
120	        // Create order
121	        String orderNumber = "ORD-" + System.currentTimeMillis() + "-" + orderSeq.incrementAndGet();
122	        String idempotencyKeyHash = idempotencyKey != null ?
123	                hashIdempotencyKey(request.getBuyerId(), idempotencyKey) : null;
124	
125	        Order order = Order.builder()
126	                .orderNumber(orderNumber)
127	                .buyerUserId(request.getBuyerId())
128	                .status(OrderStatus.PLACED)
129	                .subtotal(subtotal)
130	                .discountsTotal(pricing.getDiscountsTotal())
131	                .shippingTotal(pricing.getShippingTotal())
132	                .totalPayable(pricing.getTotalPayable())
133	                .couponId(pricing.getAppliedCouponId())
134	                .campaignId(pricing.getAppliedCampaignId())
135	                .paymentMethod(request.getPaymentMethod())
136	                .shippingCountry(request.getShippingCountry())
137	                .shippingPostalCode(request.getShippingPostalCode())
138	                .idempotencyKeyHash(idempotencyKeyHash)
139	                .items(new ArrayList<>())
140	                .build();
141	
142	        order = orderRepository.save(order);
143	
144	        // Create items
145	        List<OrderItem> items = new ArrayList<>();
146	        for (var itemDto : request.getItems()) {
147	            OrderItem item = OrderItem.builder()
148	                    .orderId(order.getId())
149	                    .sku(itemDto.getSku())
150	                    .quantity(itemDto.getQuantity())
151	                    .unitPrice(itemDto.getUnitPrice())
152	                    .lineTotal(itemDto.getUnitPrice().multiply(BigDecimal.valueOf(itemDto.getQuantity())))
153	                    .build();
154	            items.add(orderItemRepository.save(item));
155	        }
156	        order.setItems(items);
157	
158	        auditService.record(request.getBuyerId(), "ORDER", order.getId().toString(),
159	                "PLACE_ORDER", "USER_ACTION", null, orderNumber);
160	
161	        return toResponse(order);
162	    }
