377	    public OrderResponse toResponse(Order order) {
378	        // Load items from DB (since items is @Transient on Order)
379	        List<OrderItem> dbItems = order.getItems() != null && !order.getItems().isEmpty()
380	                ? order.getItems()
381	                : orderItemRepository.findByOrderId(order.getId());
382	        List<OrderItemResponse> itemResponses = dbItems.stream()
383	                .map(this::toItemResponse).collect(Collectors.toList());
384	
385	        return OrderResponse.builder()
386	                .id(order.getId())
387	                .orderNumber(order.getOrderNumber())
388	                .buyerUserId(order.getBuyerUserId())
389	                .status(order.getStatus())
390	                .subtotal(order.getSubtotal())
391	                .discountsTotal(order.getDiscountsTotal())
392	                .shippingTotal(order.getShippingTotal())
393	                .totalPayable(order.getTotalPayable())
394	                .paymentMethod(order.getPaymentMethod())
395	                .shippingCountry(order.getShippingCountry())
396	                .shippingPostalCode(order.getShippingPostalCode())
397	                .items(itemResponses)
398	                .createdAt(order.getCreatedAt())
399	                .closedAt(order.getClosedAt())
400	                .paymentConfirmedAt(order.getPaymentConfirmedAt())
401	                .build();
402	    }
