89	        wo.setTechnicianUserId(technicianId);
90	        wo.setStatus(WorkOrderStatus.ASSIGNED);
91	        workOrderRepository.save(wo);
92	
93	        // Add event
94	        addEventInternal(wo.getId(), WorkOrderEventType.TECHNICIAN_ASSIGNED,
