100	    @Transactional
101	    public WorkOrderResponse addEvent(UUID workOrderId, WorkOrderEventType type, String payload, UUID actorId) {
102	        permissionEnforcer.require("WORK_ORDER", "WRITE");
103	        WorkOrder wo = workOrderRepository.findById(workOrderId)
104	                .orElseThrow(() -> new AppException("WORK_ORDER_NOT_FOUND", "Work order not found", HttpStatus.NOT_FOUND));
105	
106	        addEventInternal(workOrderId, type, payload, actorId);
107	
108	        if (type == WorkOrderEventType.FIRST_RESPONSE_SENT && wo.getFirstRespondedAt() == null) {
109	            wo.setFirstRespondedAt(OffsetDateTime.now());
110	        }
111	        if (type == WorkOrderEventType.RESOLUTION_CONFIRMED) {
112	            wo.setResolvedAt(OffsetDateTime.now());
113	            wo.setStatus(WorkOrderStatus.RESOLVED);
114	            // Q12: auto-lock cost on resolution so it can no longer be edited
115	            workOrderCostRepository.findByWorkOrderId(workOrderId).ifPresent(cost -> {
116	                if (cost.getLockedAt() == null) {
117	                    cost.setLockedAt(OffsetDateTime.now());
118	                    cost.setApprovedStatus("APPROVED");
119	                    workOrderCostRepository.save(cost);
120	                }
121	            });
122	        }
123	        if (type == WorkOrderEventType.STATUS_UPDATED) {
124	            // Keep current status unless specified
125	            wo.setStatus(WorkOrderStatus.IN_PROGRESS);
126	        }
127	        workOrderRepository.save(wo);
128	
129	        return toResponse(wo);
130	    }
