142	    @Transactional
143	    public WorkOrderResponse updateCost(UUID workOrderId, WorkOrderCostRequest request, UUID actorId) {
144	        permissionEnforcer.require("WORK_ORDER", "WRITE");
145	        WorkOrder wo = workOrderRepository.findById(workOrderId)
146	                .orElseThrow(() -> new AppException("WORK_ORDER_NOT_FOUND", "Work order not found", HttpStatus.NOT_FOUND));
147	
148	        // Q12: cost is editable only while the work order is in early states
149	        if (wo.getStatus() == WorkOrderStatus.RESOLVED || wo.getStatus() == WorkOrderStatus.CLOSED) {
150	            throw new AppException("COST_LOCKED",
151	                    "Work order cost cannot be modified in status: " + wo.getStatus(),
152	                    HttpStatus.CONFLICT);
153	        }
154	
155	        WorkOrderCost cost = workOrderCostRepository.findByWorkOrderId(workOrderId)
156	                .orElseGet(() -> WorkOrderCost.builder()
157	                        .workOrderId(workOrderId)
158	                        .partsCost(BigDecimal.ZERO)
159	                        .laborCost(BigDecimal.ZERO)
160	                        .build());
161	
162	        if (cost.getLockedAt() != null) {
163	            throw new AppException("COST_LOCKED", "Work order cost is locked and cannot be modified", HttpStatus.CONFLICT);
164	        }
165	
166	        if (request.getPartsCost() != null) cost.setPartsCost(request.getPartsCost());
167	        if (request.getLaborCost() != null) cost.setLaborCost(request.getLaborCost());
168	        if (request.getNotes() != null) cost.setNotes(request.getNotes());
169	        workOrderCostRepository.save(cost);
170	
171	        addEventInternal(workOrderId, WorkOrderEventType.COST_UPDATED, "Cost updated", actorId);
172	
173	        return toResponse(wo);
174	    }
