202	    public WorkOrderAnalyticsResponse getAnalytics(LocalDate from, LocalDate to,
203	                                                    UUID technicianId, String statusStr) {
204	        // RLS: callers without ADMIN:READ can only see their own work orders
205	        if (!SecurityUtils.hasPermission("ADMIN", "READ")) {
206	            technicianId = SecurityUtils.getCurrentUserId();
207	        }
208	        WorkOrderStatus status = null;
209	        if (statusStr != null && !statusStr.isBlank()) {
210	            try { status = WorkOrderStatus.valueOf(statusStr); } catch (Exception e) { /* ignore */ }
211	        }
212	        OffsetDateTime fromDt = from != null
213	                ? from.atStartOfDay().atOffset(ZoneOffset.UTC)
214	                : OffsetDateTime.now().minusYears(10);
215	        OffsetDateTime toDt = to != null
216	                ? to.plusDays(1).atStartOfDay().atOffset(ZoneOffset.UTC)
217	                : OffsetDateTime.now().plusDays(1);
218	
219	        List<WorkOrder> orders = workOrderRepository.findForAnalytics(technicianId, status, fromDt, toDt);
220	
221	        long submitted = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.SUBMITTED).count();
222	        long assigned = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.ASSIGNED).count();
223	        long inProgress = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.IN_PROGRESS).count();
224	        long resolved = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.RESOLVED).count();
225	        long closed = orders.stream().filter(w -> w.getStatus() == WorkOrderStatus.CLOSED).count();
226	
227	        double avgRating = orders.stream()
228	                .mapToInt(w -> workOrderRatingRepository.findByWorkOrderId(w.getId())
229	                        .map(WorkOrderRating::getRating).orElse(0))
230	                .filter(r -> r > 0)
231	                .average().orElse(0.0);
232	
233	        BigDecimal totalParts = orders.stream()
234	                .map(w -> workOrderCostRepository.findByWorkOrderId(w.getId())
235	                        .map(WorkOrderCost::getPartsCost).orElse(BigDecimal.ZERO))
236	                .reduce(BigDecimal.ZERO, BigDecimal::add);
237	
238	        BigDecimal totalLabor = orders.stream()
239	                .map(w -> workOrderCostRepository.findByWorkOrderId(w.getId())
240	                        .map(WorkOrderCost::getLaborCost).orElse(BigDecimal.ZERO))
241	                .reduce(BigDecimal.ZERO, BigDecimal::add);
242	
243	        return WorkOrderAnalyticsResponse.builder()
244	                .total(orders.size())
245	                .submitted(submitted)
246	                .assigned(assigned)
247	                .inProgress(inProgress)
248	                .resolved(resolved)
249	                .closed(closed)
250	                .avgRating(avgRating)
251	                .totalPartsCost(totalParts)
252	                .totalLaborCost(totalLabor)
253	                .build();
254	    }
