20	        if (principal instanceof RicmsPrincipal ricmsPrincipal) {
21	            return ricmsPrincipal.getUserId();
22	        }
23	        throw new AppException("UNAUTHORIZED", "Cannot determine current user", HttpStatus.UNAUTHORIZED);
24	    }
25	
26	    public static String getCurrentUsername() {
27	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
28	        if (auth == null || !auth.isAuthenticated()) {
29	            throw new AppException("UNAUTHORIZED", "No authenticated user", HttpStatus.UNAUTHORIZED);
30	        }
31	        return auth.getName();
32	    }
33	
34	    /** Convenience: does the current principal hold ROLE_<role>? */
35	    public static boolean hasRole(String role) {
36	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
37	        if (auth == null) return false;
38	        return auth.getAuthorities().stream()
39	                .anyMatch(a -> a.getAuthority().equals("ROLE_" + role));
40	    }
41	
42	    /** Convenience: does the current principal hold PERM_<resourceType>:<operation>? */
43	    public static boolean hasPermission(String resourceType, String operation) {
44	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
45	        if (auth == null || !auth.isAuthenticated()) return false;
46	        String authority = "PERM_" + resourceType + ":" + operation;
47	        return auth.getAuthorities().stream()
48	                .anyMatch(a -> a.getAuthority().equals(authority));
49	    }
50	}
