1	package com.example.ricms.service;
2	
3	import com.example.ricms.domain.entity.Member;
4	import com.example.ricms.domain.entity.PointsLedger;
5	import com.example.ricms.domain.enums.MemberStatus;
6	import com.example.ricms.domain.enums.MemberTier;
7	import com.example.ricms.dto.response.MemberResponse;
8	import com.example.ricms.dto.response.PageResponse;
9	import com.example.ricms.dto.response.PointsLedgerResponse;
10	import com.example.ricms.exception.AppException;
11	import com.example.ricms.repository.MemberRepository;
12	import com.example.ricms.repository.PointsLedgerRepository;
13	import com.example.ricms.security.SecurityUtils;
14	import lombok.RequiredArgsConstructor;
15	import java.util.Map;
16	import lombok.extern.slf4j.Slf4j;
17	import org.springframework.data.domain.PageRequest;
18	import org.springframework.http.HttpStatus;
19	import org.springframework.stereotype.Service;
20	import org.springframework.transaction.annotation.Transactional;
21	
22	import java.math.BigDecimal;
23	import java.math.RoundingMode;
24	import java.time.OffsetDateTime;
25	import java.util.List;
26	import java.util.Optional;
27	import java.util.UUID;
28	
29	@Slf4j
30	@Service
31	@RequiredArgsConstructor
32	public class MemberService {
33	
34	    private final MemberRepository memberRepository;
35	    private final PointsLedgerRepository pointsLedgerRepository;
36	    private final AuditService auditService;
37	
38	    // ------------------------------------------------------------------
39	    // Profile & ledger (Q3 / Q4)
40	    // ------------------------------------------------------------------
41	
42	    public MemberResponse getMyProfile(UUID userId) {
43	        Member member = requireByUserId(userId);
44	        return toResponse(member);
45	    }
46	
47	    public PageResponse<PointsLedgerResponse> getPointsLedger(UUID userId, int page, int pageSize) {
48	        // RLS: non-admin callers can only view their own ledger
49	        if (!SecurityUtils.hasPermission("ADMIN", "READ")) {
50	            userId = SecurityUtils.getCurrentUserId();
51	        }
52	        Member member = requireByUserId(userId);
53	        var ledgerPage = pointsLedgerRepository.findByMemberIdOrderByCreatedAtDesc(
54	                member.getId(), PageRequest.of(page, pageSize));
55	        return PageResponse.of(ledgerPage.map(this::toLedgerResponse));
56	    }
57	
58	    // ------------------------------------------------------------------
59	    // Points accrual (Q4)
60	    // Points = floor(totalPayable) — 1 point per whole dollar after discounts.
61	    // Only persisted; the caller (OrderService) is responsible for calling
62	    // this at CONFIRMED_PAYMENT / COMPLETED state.
63	    // ------------------------------------------------------------------
64	
65	    @Transactional
66	    public void accruePoints(UUID memberId, UUID orderId, BigDecimal payableAmount) {
67	        Member member = memberRepository.findById(memberId)
68	                .orElseThrow(() -> new AppException("MEMBER_NOT_FOUND", "Member not found", HttpStatus.NOT_FOUND));
69	
70	        // 1 point per $1.00 – floor to the nearest whole dollar (Q4)
71	        long pointsEarned = payableAmount
72	                .setScale(0, RoundingMode.FLOOR)
73	                .longValue();
74	
75	        if (pointsEarned <= 0) return;
76	
77	        PointsLedger ledger = PointsLedger.builder()
78	                .memberId(memberId)
79	                .pointsDelta(pointsEarned)
80	                .sourceOrderId(orderId)
81	                .currencyAmountBasis(payableAmount)
82	                .description("Points earned for order " + orderId)
83	                .build();
84	        pointsLedgerRepository.save(ledger);
85	
86	        member.setPointsBalance(member.getPointsBalance() + pointsEarned);
87	        checkAndUpgradeTier(member);   // immediate upgrade (Q5)
88	        memberRepository.save(member);
89	    }
90	
91	    // ------------------------------------------------------------------
92	    // Tier management (Q5)
93	    // ------------------------------------------------------------------
94	
95	    /**
96	     * Upgrade tier immediately whenever the running balance crosses a threshold.
97	     * Only ever promotes – downgrade is handled by the scheduled monthly job.
98	     */
99	    public void checkAndUpgradeTier(Member member) {
100	        MemberTier target = tierForBalance(member.getPointsBalance());
101	        if (target.ordinal() > member.getTier().ordinal()) {
102	            MemberTier before = member.getTier();
103	            log.info("Upgrading member {} tier: {} → {}", member.getId(), before, target);
104	            member.setTier(target);
105	            auditService.record(null, "MEMBER", member.getId().toString(),
106	                    "TIER_CHANGE", "SYSTEM_TIER_UPGRADE",
107	                    Map.of("tier", before.name()),
108	                    Map.of("tier", target.name()));
109	        }
110	        // Intentionally no downgrade here – that is the monthly job's responsibility (Q5)
111	    }
112	
113	    /**
114	     * Monthly scheduled job: recalculate each member's tier from their
115	     * authoritative ledger sum and only LOWER the tier if warranted (Q5).
116	     * Upgrades are already handled immediately at accrual time.
117	     */
118	    @Transactional
119	    public void monthlyTierDowngrade() {
120	        log.info("Running monthly tier downgrade job");
121	        List<Member> allMembers = memberRepository.findAll();
122	        int downgraded = 0;
123	        for (Member member : allMembers) {
124	            // Authoritative balance from ledger (handles any manual adjustments)
125	            Long ledgerTotal = pointsLedgerRepository.sumPointsByMemberId(member.getId());
126	            long authoritative = ledgerTotal != null ? ledgerTotal : 0L;
127	
128	            // Sync the denormalised balance field with the ledger sum
129	            member.setPointsBalance(authoritative);
130	
131	            MemberTier correct = tierForBalance(authoritative);
132	            if (correct.ordinal() < member.getTier().ordinal()) {
133	                // Only downgrade – never promote during this job (Q5)
134	                MemberTier before = member.getTier();
135	                log.info("Downgrading member {} tier: {} → {}", member.getId(), before, correct);
136	                member.setTier(correct);
137	                downgraded++;
138	                auditService.record(null, "MEMBER", member.getId().toString(),
139	                        "TIER_CHANGE", "SYSTEM_TIER_DOWNGRADE",
140	                        Map.of("tier", before.name()),
141	                        Map.of("tier", correct.name()));
142	            }
143	        }
144	        memberRepository.saveAll(allMembers);
145	        log.info("Monthly tier downgrade complete. {} member(s) downgraded.", downgraded);
146	    }
147	
148	    private MemberTier tierForBalance(long balance) {
149	        if (balance >= 5000) return MemberTier.GOLD;
150	        if (balance >= 1000) return MemberTier.SILVER;
151	        return MemberTier.BRONZE;
152	    }
153	
154	    // ------------------------------------------------------------------
155	    // Admin status management (Q3)
156	    // ------------------------------------------------------------------
157	
158	    /**
159	     * Update a member's standing status (ACTIVE / SUSPENDED / DELINQUENT).
160	     * Member pricing is gated on ACTIVE status (Q3), so changing status
161	     * immediately affects pricing eligibility on subsequent orders.
162	     */
163	    @Transactional
164	    public MemberResponse updateStatus(UUID memberId, MemberStatus newStatus, UUID actorId) {
165	        Member member = memberRepository.findById(memberId)
166	                .orElseThrow(() -> new AppException("MEMBER_NOT_FOUND", "Member not found", HttpStatus.NOT_FOUND));
167	
168	        MemberStatus previous = member.getStatus();
169	        member.setStatus(newStatus);
170	
171	        // Record when the member entered good standing
172	        if (newStatus == MemberStatus.ACTIVE && previous != MemberStatus.ACTIVE) {
173	            member.setGoodStandingSince(OffsetDateTime.now());
174	        }
175	
176	        memberRepository.save(member);
177	        log.info("Member {} status changed by actor {}: {} → {}", memberId, actorId, previous, newStatus);
178	        return toResponse(member);
179	    }
180	
181	    /**
182	     * Create a member profile for a new user.
183	     * Called automatically by UserService.createUser so every user starts
184	     * with a BRONZE / ACTIVE membership.
185	     */
186	    @Transactional
187	    public Member createForUser(UUID userId) {
188	        // Idempotent: return existing if already created
189	        Optional<Member> existing = memberRepository.findByUserId(userId);
190	        if (existing.isPresent()) return existing.get();
191	
192	        Member member = Member.builder()
193	                .userId(userId)
194	                .status(MemberStatus.ACTIVE)
195	                .tier(MemberTier.BRONZE)
196	                .pointsBalance(0L)
197	                .goodStandingSince(OffsetDateTime.now())
198	                .build();
199	        return memberRepository.save(member);
200	    }
201	
202	    // ------------------------------------------------------------------
203	    // Mapping helpers
204	    // ------------------------------------------------------------------
205	
206	    public MemberResponse toResponse(Member member) {
207	        return MemberResponse.builder()
208	                .memberId(member.getId())
209	                .userId(member.getUserId())
210	                .status(member.getStatus())
211	                .tier(member.getTier())
212	                .pointsBalance(member.getPointsBalance())
213	                .build();
214	    }
215	
216	    private PointsLedgerResponse toLedgerResponse(PointsLedger p) {
217	        return PointsLedgerResponse.builder()
218	                .id(p.getId())
219	                .pointsDelta(p.getPointsDelta())
220	                .sourceOrderId(p.getSourceOrderId())
221	                .currencyAmountBasis(p.getCurrencyAmountBasis())
222	                .description(p.getDescription())
223	                .createdAt(p.getCreatedAt())
224	                .build();
225	    }
226	
227	    private Member requireByUserId(UUID userId) {
228	        return memberRepository.findByUserId(userId)
229	                .orElseThrow(() -> new AppException(
230	                        "MEMBER_NOT_FOUND", "Member profile not found", HttpStatus.NOT_FOUND));
231	    }
232	}
