1	package com.example.ricms.security;
2	
3	import com.example.ricms.exception.AppException;
4	import org.springframework.http.HttpStatus;
5	import org.springframework.security.core.Authentication;
6	import org.springframework.security.core.context.SecurityContextHolder;
7	import org.springframework.stereotype.Component;
8	
9	import java.util.UUID;
10	
11	/**
12	 * Centralised fine-grained permission enforcement (Q1).
13	 *
14	 * Authorities loaded at login time by UserDetailsServiceImpl have the form:
15	 *   ROLE_<name>      – e.g. ROLE_ADMIN
16	 *   PERM_<RT>:<OP>   – e.g. PERM_ORDER:WRITE
17	 *
18	 * Calling require() on a service write path before any mutation ensures every
19	 * privileged action is gated. requireSelf() adds an optional ownership check:
20	 * the caller must be the target user OR possess USER:WRITE (admin bypass).
21	 */
22	@Component
23	public class PermissionEnforcer {
24	
25	    /**
26	     * Throw 403 if the current principal does not hold the requested permission.
27	     */
28	    public void require(String resourceType, String operation) {
29	        Authentication auth = currentAuth();
30	        String authority = "PERM_" + resourceType + ":" + operation;
31	        boolean granted = auth.getAuthorities().stream()
32	                .anyMatch(a -> a.getAuthority().equals(authority));
33	        if (!granted) {
34	            throw new AppException("FORBIDDEN",
35	                    "Missing required permission: " + resourceType + ":" + operation,
36	                    HttpStatus.FORBIDDEN);
37	        }
38	    }
39	
40	    /**
41	     * Ownership row-level check: caller must be targetUserId OR hold USER:WRITE.
42	     * Use for self-service endpoints (e.g. password rotation).
43	     */
44	    public void requireSelf(UUID targetUserId) {
45	        UUID callerId = SecurityUtils.getCurrentUserId();
46	        if (callerId.equals(targetUserId)) {
47	            return; // owner – allow
48	        }
49	        // Non-owner must have USER:WRITE (admin bypass)
50	        Authentication auth = currentAuth();
51	        boolean adminBypass = auth.getAuthorities().stream()
52	                .anyMatch(a -> a.getAuthority().equals("PERM_USER:WRITE"));
53	        if (!adminBypass) {
54	            throw new AppException("FORBIDDEN",
55	                    "You may only modify your own resource", HttpStatus.FORBIDDEN);
56	        }
57	    }
58	
59	    /** Non-throwing check – use when the result gates optional behaviour. */
60	    public boolean hasPermission(String resourceType, String operation) {
61	        try {
62	            Authentication auth = currentAuth();
63	            String authority = "PERM_" + resourceType + ":" + operation;
64	            return auth.getAuthorities().stream()
65	                    .anyMatch(a -> a.getAuthority().equals(authority));
