    @Mock OrderRepository orderRepository;
    @Mock OrderItemRepository orderItemRepository;
    @Mock OrderNoteRepository orderNoteRepository;
    @Mock InventoryRepository inventoryRepository;
    @Mock AttachmentRepository attachmentRepository;
    @Mock MemberRepository memberRepository;
    @Mock MemberService memberService;
    @Mock PricingEngine pricingEngine;
    @Mock AuditService auditService;
    @Mock PermissionEnforcer permissionEnforcer;

    OrderService service;

    static final UUID BUYER_ID  = UUID.randomUUID();
    static final UUID OTHER_ID  = UUID.randomUUID();
    static final UUID ORDER_ID  = UUID.randomUUID();
    static final String IKEY    = "test-idem-key";

    @BeforeEach
    void setUp() {
        service = new OrderService(
                orderRepository, orderItemRepository, orderNoteRepository,
                inventoryRepository, attachmentRepository, memberRepository,
                memberService, pricingEngine, auditService, permissionEnforcer);
    }

    @AfterEach
    void clearContext() {
        SecurityContextHolder.clearContext();
    }

    // -----------------------------------------------------------------------
    // Helpers
    // -----------------------------------------------------------------------

    private void setUpSecurityContext(UUID userId, String... extraPerms) {
        List<SimpleGrantedAuthority> auths = new java.util.ArrayList<>();
        auths.add(new SimpleGrantedAuthority("PERM_ORDER:READ"));
        auths.add(new SimpleGrantedAuthority("PERM_ORDER:WRITE"));
        for (String p : extraPerms) auths.add(new SimpleGrantedAuthority(p));

        RicmsPrincipal principal = new RicmsPrincipal(userId, "user", "", auths);
        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken(principal, null, auths));
    }

    private Order buildOrder(UUID buyerId, OrderStatus status) {
        return Order.builder()
                .id(ORDER_ID)
                .orderNumber("ORD-TEST")
                .buyerUserId(buyerId)
                .status(status)
                .subtotal(BigDecimal.TEN)
                .discountsTotal(BigDecimal.ZERO)
                .shippingTotal(BigDecimal.ONE)
                .totalPayable(BigDecimal.valueOf(11))
                .paymentMethod(PaymentMethod.CASH_ON_DELIVERY)
                .createdAt(OffsetDateTime.now())
                .build();
    }

    private PlaceOrderRequest validRequest() {
        OrderItemDto item = new OrderItemDto();
        item.setSku("SKU-001");
        item.setQuantity(1);
        item.setUnitPrice(BigDecimal.TEN);

        PlaceOrderRequest r = new PlaceOrderRequest();
        r.setBuyerId(BUYER_ID);
        r.setItems(List.of(item));
        r.setPaymentMethod(PaymentMethod.CASH_ON_DELIVERY);
        r.setShippingCountry("US");
        return r;
    }

    // -----------------------------------------------------------------------
    // A) Object-level authorization (IDOR prevention)
    // -----------------------------------------------------------------------

    @Test
    void getOrder_nonOwner_throws403() {
        setUpSecurityContext(OTHER_ID); // caller is OTHER_ID, not the order's owner
        Order order = buildOrder(BUYER_ID, OrderStatus.PLACED);
        when(orderRepository.findById(ORDER_ID)).thenReturn(Optional.of(order));

        assertThatThrownBy(() -> service.getOrder(ORDER_ID))
                .isInstanceOf(AppException.class)
                .hasMessageContaining("access to this order");

        verify(auditService, never()).record(any(), any(), any(), any(), any(), any(), any());
    }

    @Test
    void getOrder_owner_succeeds() {
        setUpSecurityContext(BUYER_ID);
        Order order = buildOrder(BUYER_ID, OrderStatus.PLACED);
        when(orderRepository.findById(ORDER_ID)).thenReturn(Optional.of(order));
        when(orderItemRepository.findByOrderId(ORDER_ID)).thenReturn(List.of());

        var result = service.getOrder(ORDER_ID);
        assertThat(result.getId()).isEqualTo(ORDER_ID);
    }

    @Test
    void getOrder_adminBypass_succeeds() {
        // Admin (PERM_ADMIN:READ) can access any order
        setUpSecurityContext(OTHER_ID, "PERM_ADMIN:READ");
        Order order = buildOrder(BUYER_ID, OrderStatus.PLACED);
        when(orderRepository.findById(ORDER_ID)).thenReturn(Optional.of(order));
        when(orderItemRepository.findByOrderId(ORDER_ID)).thenReturn(List.of());

        var result = service.getOrder(ORDER_ID);
        assertThat(result.getId()).isEqualTo(ORDER_ID);
    }

    @Test
    void confirmPayment_nonOwner_throws403() {
        setUpSecurityContext(OTHER_ID);
        Order order = buildOrder(BUYER_ID, OrderStatus.PLACED);
        when(orderRepository.findById(ORDER_ID)).thenReturn(Optional.of(order));

        assertThatThrownBy(() -> service.confirmPayment(ORDER_ID, "PAY-REF"))
                .isInstanceOf(AppException.class)
                .hasMessageContaining("access to this order");
    }

    // -----------------------------------------------------------------------
    // C) Idempotency: placeOrder returns OrderPlacementResult with replay flag
    // -----------------------------------------------------------------------

    @Test
    void placeOrder_newOrder_returns201Semantics() {
        setUpSecurityContext(BUYER_ID);

        Inventory inv = Inventory.builder()
                .sku("SKU-001").onHand(10).reserved(0).build();
        when(inventoryRepository.findBySkuWithLock("SKU-001")).thenReturn(Optional.of(inv));
        when(orderRepository.findByBuyerUserIdAndIdempotencyKeyHash(any(), any()))
                .thenReturn(Optional.empty());

        PricingResult pricing = PricingResult.builder()
                .discountsTotal(BigDecimal.ZERO)
                .shippingTotal(BigDecimal.valueOf(10))
                .totalPayable(BigDecimal.valueOf(20))
                .build();
        when(pricingEngine.computePricing(any(), any(), any(), any(), any())).thenReturn(pricing);

        Order saved = buildOrder(BUYER_ID, OrderStatus.PLACED);
        when(orderRepository.save(any())).thenReturn(saved);
        when(orderItemRepository.save(any())).thenAnswer(inv2 -> inv2.getArgument(0));
        when(orderItemRepository.findByOrderId(any())).thenReturn(List.of());

        OrderPlacementResult result = service.placeOrder(validRequest(), IKEY);

        assertThat(result.replay()).isFalse();
        assertThat(result.order()).isNotNull();
    }

    @Test
    void placeOrder_idempotencyReplay_returns200Semantics() {
        setUpSecurityContext(BUYER_ID);

        Order existing = buildOrder(BUYER_ID, OrderStatus.PLACED);
        existing = Order.builder()
                .id(ORDER_ID).orderNumber("ORD-REPLAY").buyerUserId(BUYER_ID)
                .status(OrderStatus.PLACED).subtotal(BigDecimal.TEN)
                .discountsTotal(BigDecimal.ZERO).shippingTotal(BigDecimal.ONE)
                .totalPayable(BigDecimal.valueOf(11))
                .paymentMethod(PaymentMethod.CASH_ON_DELIVERY)
                .createdAt(OffsetDateTime.now()) // within 10-min window
                .build();

        when(orderRepository.findByBuyerUserIdAndIdempotencyKeyHash(any(), any()))
                .thenReturn(Optional.of(existing));
        when(orderItemRepository.findByOrderId(any())).thenReturn(List.of());

        OrderPlacementResult result = service.placeOrder(validRequest(), IKEY);

        assertThat(result.replay()).isTrue();
        assertThat(result.order().getOrderNumber()).isEqualTo("ORD-REPLAY");
        // No new order saved, no inventory touched
        verify(orderRepository, never()).save(any());
        verify(inventoryRepository, never()).findBySkuWithLock(any());
    }

    // -----------------------------------------------------------------------
    // D) Audit emission
    // -----------------------------------------------------------------------

    @Test
    void fulfillOrder_emitsAuditEvent() {
        setUpSecurityContext(BUYER_ID);

        Order order = buildOrder(BUYER_ID, OrderStatus.CONFIRMED_PAYMENT);
        when(orderRepository.findById(ORDER_ID)).thenReturn(Optional.of(order));
        when(orderItemRepository.findByOrderId(ORDER_ID)).thenReturn(List.of());

        Inventory inv = Inventory.builder()
                .sku("SKU-001").onHand(5).reserved(2).build();
        // No items → no inventory lookups needed; empty skuQuantities means no insufficientSkus

        when(orderRepository.save(any())).thenReturn(order);
        when(orderItemRepository.findByOrderId(ORDER_ID)).thenReturn(List.of());

        service.fulfillOrder(ORDER_ID);

        verify(auditService).record(
                eq(BUYER_ID), eq("ORDER"), eq(ORDER_ID.toString()),
                eq("FULFILL_ORDER"), eq("USER_ACTION"), any(), any());
    }
}
